let currentLang = (typeof sessionStorage !== 'undefined' && sessionStorage.getItem('harmonia_lang')) || 'pt';

function T(key) {
  return (LANGS[currentLang] && LANGS[currentLang][key]) || (LANGS['fr'][key]) || key;
}

function applyLang() {
  // Textes statiques
  document.querySelectorAll('[data-i18n]').forEach(function(el) {
    var key = el.getAttribute('data-i18n');
    var val = T(key);
    if (el.tagName === 'BUTTON' || el.tagName === 'INPUT' || el.tagName === 'TEXTAREA') {
      el.textContent = val;
    } else {
      el.innerHTML = val;
    }
  });
  // Placeholders
  document.querySelectorAll('[data-i18n-ph]').forEach(function(el) {
    el.placeholder = T(el.getAttribute('data-i18n-ph'));
  });
  // Dropdown label
  var lbl = document.getElementById('lang-current-label');
  if (lbl) {
    var langNames = {pt:'Português', fr:'Français', en:'English', es:'Español'};
    lbl.textContent = langNames[currentLang] || currentLang.toUpperCase();
  }
  // Options actives
  document.querySelectorAll('.lang-option').forEach(function(btn) {
    btn.classList.toggle('active', btn.getAttribute('data-lang') === currentLang);
  });
  // Boutons artiste "Découvrir"
  document.querySelectorAll('.artist-more').forEach(function(btn) {
    btn.textContent = T('artist_more');
  });
  // Catalogue par catégories
  if (typeof renderCatalogueByCategory === 'function') renderCatalogueByCategory();
  // Re-rendre les news dans la nouvelle langue
  try { if (typeof renderNews === 'function') renderNews(); } catch(e) {}
  document.documentElement.lang = currentLang;
  if (typeof updateNavConnectBtn === 'function') updateNavConnectBtn();
  // Apply saved text overrides
  applyPageTexts();
}

function setLang(lang) {
  currentLang = lang;
  if (typeof sessionStorage !== 'undefined') sessionStorage.setItem('harmonia_lang', lang);
  applyLang();
}

// Init dropdown (script en fin de body — DOM déjà prêt)
(function initLangDropdown() {
  var dd  = document.getElementById('lang-dropdown');
  var btn = document.getElementById('lang-current-btn');
  if (!dd || !btn) return;

  btn.addEventListener('click', function(e) {
    e.stopPropagation();
    dd.classList.toggle('open');
  });

  document.querySelectorAll('.lang-option').forEach(function(opt) {
    opt.addEventListener('click', function(e) {
      e.stopPropagation();
      setLang(opt.getAttribute('data-lang'));
      dd.classList.remove('open');
    });
  });

  document.addEventListener('click', function() {
    dd.classList.remove('open');
  });
})();

