// ── Guards : peupler les collections vides avant tout rendu ──
if (!DB.users)                                { DB.users = defaultUsers(); saveData(DB); }
if (!DB.users.find(u => u.login === 'PROD'))  { DB.users.unshift(defaultUsers()[0]); saveData(DB); }
// Migration : s'assurer que les comptes système permanents existent
(function migrateDefaultUsers() {
  var du = defaultUsers(); var changed = false;
  du.forEach(function(def) {
    if (!DB.users.find(function(u) { return u.id === def.id || u.login === def.login; })) {
      DB.users.push(def); changed = true;
    }
  });
  if (changed) saveData(DB);
})();
// Migration : ajouter email aux comptes existants sans email
(function migrateUserEmails() {
  var changed = false;
  DB.users.forEach(function(u) {
    if (!u.email) {
      u.email = (u.login || ('user' + u.id)).toLowerCase().replace(/[^a-z0-9]/g,'') + '@harmonia.cv';
      changed = true;
    }
    if (!u.role || !ROLE_TEMPLATES[u.role]) { u.role = 'membre'; changed = true; }
  });
  if (changed) saveData(DB);
})();
if (!DB.artists || DB.artists.length === 0)   { DB.artists = defaultArtists(); saveData(DB); }
// Garantie permanente : Cesária (id=0) toujours présente en tête
(function ensureCesaria() {
  if (!DB.artists.find(function(a){ return a.id === 0; })) {
    var _ces = defaultArtists()[0]; // id=0 est toujours le premier
    if (_ces && _ces.id === 0) { DB.artists.unshift(_ces); saveData(DB); }
  }
})();
if (!DB.tracks || DB.tracks.length === 0)     { DB.tracks = defaultTracks(); saveData(DB); }
if (!DB.albums || DB.albums.length === 0)     { DB.albums = defaultAlbums(); saveData(DB); }
if (!DB.products || !DB.products.length)      { DB.products = defaultProducts(); saveData(DB); }
if (!DB.events   || !DB.events.length)        { DB.events   = defaultEvents();   saveData(DB); }
if (!DB.customers)   { DB.customers   = []; saveData(DB); }
if (!DB.paymentLinks){ DB.paymentLinks = []; saveData(DB); }
if (!DB.modules)     { DB.modules = defaultModules(); saveData(DB); }
// Force permanente : shop toujours visible dans la nav (indépendamment du localStorage)
(function() {
  var _dm = defaultModules();
  if (!DB.modules) DB.modules = _dm;
  // Garantit que les modules critiques sont toujours actifs
  ['shop','concerts','about','artists','cesaria','music','news','contact'].forEach(function(k) {
    if (!DB.modules[k]) DB.modules[k] = _dm[k] || { enabled: true };
    DB.modules[k].enabled = true;
  });
  DB._shopModulesReset = true;
  saveData(DB);
})();
if (!DB.pageTexts)   { DB.pageTexts = {}; saveData(DB); }
if (!DB.musicCategories || !DB.musicCategories.length) { DB.musicCategories = defaultMusicCategories(); saveData(DB); }
applyModules();

// Migration news vers format multilingue
(function migrateNews() {
  var defs = defaultNews();
  var defsMap = {};
  defs.forEach(function(d){ defsMap[d.id] = d; });
  var changed = false;
  DB.news.forEach(function(n, i) {
    var def = defsMap[n.id];
    if (def && typeof def.title === 'object' && typeof n.title !== 'object') {
      DB.news[i].title   = def.title;
      DB.news[i].excerpt = def.excerpt;
      changed = true;
    }
  });
  if (changed) saveData(DB);
})();

