(function initLang() {
  try {
    var saved = (typeof sessionStorage !== 'undefined') ? sessionStorage.getItem('harmonia_lang') : null;
    if (saved && LANGS[saved]) {
      currentLang = saved;
    }
  } catch(e) {}
  // applyLang garanti même si les fonctions de rendu échouent
  try { applyLang(); } catch(e) { console.warn('applyLang error:', e); }
})();

