// Patch doLogin / doLogout to update nav btn
// updateNavConnectBtn() intégré directement dans doLogin/doLogout

// --- Mot de passe oublié (non-admin) ---
function openForgot(e) {
  e && e.preventDefault();
  document.getElementById('forgot-err').classList.remove('show');
  document.getElementById('forgot-ok').classList.remove('show');
  ['forgot-login','forgot-new','forgot-confirm'].forEach(id => document.getElementById(id).value = '');
  document.getElementById('forgot-modal').classList.add('active');
}

function closeForgot() {
  document.getElementById('forgot-modal').classList.remove('active');
}

function submitForgot() {
  const login   = document.getElementById('forgot-login').value.trim();
  const newPwd  = document.getElementById('forgot-new').value;
  const confirm = document.getElementById('forgot-confirm').value;
  const errEl   = document.getElementById('forgot-err');
  const okEl    = document.getElementById('forgot-ok');

  errEl.classList.remove('show');
  okEl.classList.remove('show');

  if (!login || !newPwd || !confirm) {
    errEl.textContent = 'Tous les champs sont requis.';
    errEl.classList.add('show'); return;
  }
  if (newPwd !== confirm) {
    errEl.textContent = T('change_err_match');
    errEl.classList.add('show'); return;
  }
  if (newPwd.length < 6) {
    errEl.textContent = 'Le mot de passe doit contenir au moins 6 caractères.';
    errEl.classList.add('show'); return;
  }

  const user = DB.users.find(u => u.login === login);
  if (!user) {
    errEl.textContent = 'Identifiant non reconnu. Contactez votre administrateur.';
    errEl.classList.add('show'); return;
  }

  // Superadmin cannot reset via this form (must use change-pwd with old pass)
  if (user.role === 'superadmin') {
    errEl.textContent = 'Le Super-Admin doit utiliser le formulaire "Changer mot de passe" depuis l\'espace admin.';
    errEl.classList.add('show'); return;
  }

  user.pass = newPwd;
  saveData(DB);
  okEl.classList.add('show');
  setTimeout(closeForgot, 2000);
}

// --- Changer mot de passe (admin, avec ancien mot de passe) ---
function openChangePwd() {
  document.getElementById('change-err').classList.remove('show');
  document.getElementById('change-ok').classList.remove('show');
  ['change-old','change-new','change-confirm'].forEach(id => document.getElementById(id).value = '');
  document.getElementById('change-pwd-modal').classList.add('active');
}

function closeChangePwd() {
  document.getElementById('change-pwd-modal').classList.remove('active');
}

function submitChangePwd() {
  const oldPwd  = document.getElementById('change-old').value;
  const newPwd  = document.getElementById('change-new').value;
  const confirm = document.getElementById('change-confirm').value;
  const errEl   = document.getElementById('change-err');
  const okEl    = document.getElementById('change-ok');

  errEl.classList.remove('show');
  okEl.classList.remove('show');

  if (!oldPwd || !newPwd || !confirm) {
    errEl.textContent = 'Tous les champs sont requis.';
    errEl.classList.add('show'); return;
  }
  if (!currentUser) {
    errEl.textContent = 'Vous devez être connecté.';
    errEl.classList.add('show'); return;
  }
  if (currentUser.pass !== oldPwd) {
    errEl.textContent = T('change_err_wrong');
    errEl.classList.add('show'); return;
  }
  if (newPwd !== confirm) {
    errEl.textContent = T('change_err_match');
    errEl.classList.add('show'); return;
  }
  if (newPwd.length < 6) {
    errEl.textContent = 'Le mot de passe doit contenir au moins 6 caractères.';
    errEl.classList.add('show'); return;
  }
  if (newPwd === oldPwd) {
    errEl.textContent = 'Le nouveau mot de passe doit être différent de l\'ancien.';
    errEl.classList.add('show'); return;
  }

  // Update in DB
  const userInDB = DB.users.find(u => u.id === currentUser.id);
  if (userInDB) { userInDB.pass = newPwd; currentUser.pass = newPwd; saveData(DB); }

  okEl.classList.add('show');
  setTimeout(closeChangePwd, 2000);
}

// Close pwd modals on overlay click
