var DB = loadData();
var currentUser = null; // logged-in user object

// ── Restore session across page navigation ──
// Script en fin de <body> → DOMContentLoaded déjà fired → exécuter directement
(function restoreSession() {
  try {
    var saved = sessionStorage.getItem('harmonia_user');
    if (!saved) return;
    var u = JSON.parse(saved);
    // Recherche loose (== au lieu de ===) pour robustesse face aux types string/number
    // eslint-disable-next-line eqeqeq
    var dbUser = DB.users.find(function(x){ return x.id == u.id; });
    if (dbUser) {
      currentUser = dbUser;
      if (typeof applyPermissions    === 'function') applyPermissions();
      if (typeof initInlineEditBtn   === 'function') initInlineEditBtn();
      if (typeof updateNavConnectBtn === 'function') updateNavConnectBtn();
      if (typeof applyPageTexts      === 'function') applyPageTexts();
      // Admins : sur admin.html → afficher le panel ; ailleurs → juste la nav
      if (dbUser.role !== 'membre') {
        if (typeof window._adminPageShowPanel === 'function') {
          window._adminPageShowPanel();
        }
        // Sur les pages publiques : aucun drawer, le bouton nav gère l'accès à admin.html
      }
    } else if (u && u.role && u.role !== 'membre') {
      // localStorage vidé → user introuvable dans DB reconstruit.
      // Conserver la session en mémoire depuis sessionStorage.
      // admin.html se chargera de l'afficher via tryRestoreAdminSession.
      currentUser = {
        id:          u.id,
        login:       u.login   || u.email || '',
        email:       u.email   || '',
        name:        u.name    || 'Administrateur',
        role:        u.role,
        permissions: u.permissions || {}
      };
      if (typeof applyPermissions    === 'function') applyPermissions();
      if (typeof updateNavConnectBtn === 'function') updateNavConnectBtn();
      if (typeof window._adminPageShowPanel === 'function') {
        window._adminPageShowPanel();
      }
    } else {
      // Session invalide ou membre sans compte DB → supprimer
      sessionStorage.removeItem('harmonia_user');
    }
  } catch(e) {}
})();

