// ========================
// PERMISSION HELPERS
// ========================
function can(section, action) {
  if (!currentUser) return false;
  const p = currentUser.permissions;
  return !!(p && p[section] && p[section][action]);
}

function isSuperAdmin() {
  return currentUser && currentUser.role === 'superadmin';
}


// ═══════════════════════════════════════════════════════════
// ITEM ACTIVE/INACTIVE STATE MANAGEMENT
// ═══════════════════════════════════════════════════════════
function isItemActive(type, id) {
  var key = type + '_' + id;
  var states = (DB && DB.itemStates) || {};
  return states.hasOwnProperty(key) ? states[key] : true;
}

function toggleItemActive(type, id) {
  if (!DB.itemStates) DB.itemStates = {};
  var key = type + '_' + id;
  DB.itemStates[key] = !isItemActive(type, id);
  saveData(DB);
  // Update the card's visual state in-place
  var card = document.querySelector('[data-item-type="' + type + '"][data-item-id="' + id + '"]');
  if (card) {
    var active = isItemActive(type, id);
    // Update inactive class
    if (active) { card.classList.remove('item-card-inactive'); }
    else { card.classList.add('item-card-inactive'); }
    // Update toggle visual
    var wrap = card.querySelector('.item-toggle-wrap');
    if (wrap) {
      var track = wrap.querySelector('div');
      var thumb = track ? track.querySelector('div') : null;
      var lbl = wrap.querySelector('span');
      if (track) track.style.background = active ? '#0a9e6e' : '#444';
      if (thumb) thumb.style.left = active ? '18px' : '2px';
      if (lbl) lbl.textContent = active ? 'Actif' : 'Inactif';
    }
  }
}

function buildItemToggle(type, id, active) {
  var state = active ? 'on' : 'off';
  var label = active ? 'Actif' : 'Inactif';
  return '<div class="item-toggle-wrap" data-toggle-type="' + type + '" data-toggle-id="' + id + '">'
    + '<div class="item-toggle-track item-toggle-' + state + '"><div class="item-toggle-thumb"></div></div>'
    + '<span class="item-toggle-label">' + label + '</span>'
    + '</div>';
}

function _attachItemToggles() {
  document.querySelectorAll('.item-toggle-wrap').forEach(function(el) {
    el.onclick = function(e) {
      e.stopPropagation();
      toggleItemActive(el.dataset.toggleType, +el.dataset.toggleId);
    };
  });
}

// ═══════════════════════════════════════════════════════════
// INLINE EDITING SYSTEM
// ═══════════════════════════════════════════════════════════
var _editModeActive = false;

function applyPageTexts() {
  if (!DB || !DB.pageTexts) return;
  Object.keys(DB.pageTexts).forEach(function(key) {
    var val = DB.pageTexts[key];
    if (!val) return;
    document.querySelectorAll('[data-editable-key="' + key + '"]:not([contenteditable="true"])').forEach(function(el) {
      el.innerHTML = val;
    });
  });
}

function initInlineEditBtn() {
  var existing = document.getElementById('inline-edit-fab');
  if (existing) { existing.style.display = canEditContent() ? '' : 'none'; return; }
  if (!canEditContent()) return;

  var fab = document.createElement('button');
  fab.id = 'inline-edit-fab';
  fab.innerHTML = '&#9998; Mode &Eacute;dition';
  fab.style.cssText = 'position:fixed;bottom:80px;right:24px;z-index:89999;background:#0d2618;border:1px solid rgba(46,204,128,0.5);color:#2ecc80;font-family:Arial,sans-serif;font-size:10px;letter-spacing:2px;text-transform:uppercase;padding:10px 20px;cursor:pointer;border-radius:2px;transition:all 0.25s;box-shadow:0 4px 20px rgba(0,0,0,0.4);';
  fab.onmouseenter = function(){ fab.style.background='rgba(46,204,128,0.12)'; };
  fab.onmouseleave = function(){ if(!_editModeActive) fab.style.background='#0d2618'; };
  fab.onclick = toggleEditMode;
  document.body.appendChild(fab);
}

var _editModeActive = false;
var _pendingEdits   = {};   // key -> {el, original, current}

function _rerenderItemSections() {
  try { renderArtists(); } catch(e) { console.warn('renderArtists error:', e); }
  try { if(typeof renderArtistsByCategory === 'function') renderArtistsByCategory(); } catch(e) { console.warn('renderArtistsByCategory error:', e); }
  try { renderNews(); } catch(e) { console.warn('renderNews error:', e); }
  try { if(typeof renderShopAlbums === 'function') renderShopAlbums(); } catch(e) { console.warn('renderShopAlbums error:', e); }
  try { if(typeof renderShopConcerts === 'function') renderShopConcerts(); } catch(e) { console.warn('renderShopConcerts error:', e); }
}

function _injectItemToggles() {
  if (!(typeof isEditor === 'function' && isEditor())) return;
  document.querySelectorAll('[data-item-type][data-item-id]').forEach(function(card) {
    if (card.querySelector('.item-toggle-wrap')) return;
    var itemType = card.dataset.itemType;
    var id = +card.dataset.itemId;
    var active = (typeof isItemActive === 'function') ? isItemActive(itemType, id) : true;
    // Ensure position context
    if (!card.style.position) card.style.position = 'relative';
    // Create toggle wrapper
    var wrap = document.createElement('div');
    wrap.className = 'item-toggle-wrap';
    wrap.dataset.toggleType = itemType;
    wrap.dataset.toggleId = id;
    wrap.style.cssText = 'position:absolute;top:10px;right:10px;z-index:9999;display:flex;align-items:center;gap:8px;cursor:pointer;background:rgba(5,20,10,0.92);padding:5px 10px;border-radius:20px;border:1px solid rgba(46,204,128,0.4);box-shadow:0 2px 12px rgba(0,0,0,0.6);';
    wrap.onclick = (function(t, i) { return function(e) { e.stopPropagation(); toggleItemActive(t, i); }; })(itemType, id);
    // Track
    var track = document.createElement('div');
    track.style.cssText = 'width:36px;height:20px;border-radius:10px;position:relative;transition:background 0.25s;flex-shrink:0;background:' + (active ? '#0a9e6e' : '#444') + ';';
    var thumb = document.createElement('div');
    thumb.style.cssText = 'position:absolute;top:2px;width:16px;height:16px;border-radius:50%;background:#fff;transition:left 0.25s;box-shadow:0 1px 4px rgba(0,0,0,0.3);left:' + (active ? '18px' : '2px') + ';';
    track.appendChild(thumb);
    // Label
    var label = document.createElement('span');
    label.style.cssText = 'font-family:Arial,sans-serif;font-size:10px;letter-spacing:1px;text-transform:uppercase;color:#ccc;white-space:nowrap;';
    label.textContent = active ? 'Actif' : 'Inactif';
    wrap.appendChild(track);
    wrap.appendChild(label);
    // Pour les cartes artistes : forcer un stacking context avec z-index:0
    // z-index != auto => la carte crée un contexte d'empilement local
    if (itemType === 'artist') {
      card.style.zIndex = '0';
    }
    card.appendChild(wrap);
    // Apply inactive visual
    if (!active) { card.classList.add('item-card-inactive'); }
  });
}

function _removeItemToggles() {
  document.querySelectorAll('.item-toggle-wrap').forEach(function(el) { el.remove(); });
  document.querySelectorAll('.item-card-inactive').forEach(function(el) { el.classList.remove('item-card-inactive'); });
  document.querySelectorAll('[data-item-type="artist"]').forEach(function(el) { el.style.zIndex = ''; });
}

function toggleEditMode() {
  _editModeActive = !_editModeActive;
  var fab = document.getElementById('inline-edit-fab');
  if (_editModeActive) {
    if (fab) { fab.innerHTML = '&#10006; Quitter &eacute;dition'; fab.style.background='rgba(46,204,128,0.12)'; }
    _pendingEdits = {};
    document.body.classList.add('edit-mode-active');
    _activateEditables();
    _showEditBar();
    _rerenderItemSections();
    setTimeout(function() { _injectItemToggles(); }, 50);
  } else {
    _cancelAllEdits();
  }
}

function _activateEditables() {
  document.querySelectorAll('[data-editable-key]').forEach(function(el) {
    var key = el.getAttribute('data-editable-key');
    el.setAttribute('contenteditable', 'true');
    el.style.outline    = '2px dashed rgba(46,204,128,0.5)';
    el.style.minHeight  = '1em';
    el.style.cursor     = 'text';
    el.setAttribute('data-original', el.innerHTML);
    // Track changes
    el.addEventListener('input', _onEditInput);
  });
}

function _deactivateEditables() {
  document.querySelectorAll('[data-editable-key]').forEach(function(el) {
    el.removeAttribute('contenteditable');
    el.style.outline   = '';
    el.style.cursor    = '';
    el.style.minHeight = '';
    el.removeEventListener('input', _onEditInput);
  });
}

function _onEditInput() {
  var key = this.getAttribute('data-editable-key');
  _pendingEdits[key] = { el: this, value: this.innerHTML };
  // Highlight edited element
  this.style.outline = '2px solid #2ecc80';
  // Update counter in bar
  var cnt = document.getElementById('edit-bar-count');
  var n = Object.keys(_pendingEdits).length;
  if (cnt) cnt.textContent = n + ' modification' + (n > 1 ? 's' : '');
}

function _showEditBar() {
  var existing = document.getElementById('inline-edit-bar');
  if (existing) existing.remove();

  var bar = document.createElement('div');
  bar.id = 'inline-edit-bar';
  bar.style.cssText = 'position:fixed;bottom:0;left:0;right:0;z-index:99998;background:#061a10;border-top:1px solid rgba(46,204,128,0.3);display:flex;align-items:center;justify-content:space-between;padding:12px 32px;box-shadow:0 -4px 24px rgba(0,0,0,0.5);';
  bar.innerHTML =
    '<div style="display:flex;align-items:center;gap:16px;">'
    + '<span style="font-family:Arial;font-size:9px;letter-spacing:3px;text-transform:uppercase;color:#2ecc80;">&#9998; MODE &Eacute;DITION</span>'
    + '<span id="edit-bar-count" style="font-family:Arial;font-size:11px;color:rgba(255,255,255,0.45);">0 modification</span>'
    + '</div>'
    + '<div style="display:flex;gap:12px;">'
    + '<button onclick="saveAllEdits()" style="background:#1f9e5c;border:none;color:#fff;font-family:Arial;font-size:10px;letter-spacing:2px;text-transform:uppercase;padding:10px 28px;cursor:pointer;transition:background 0.2s;" onmouseover="this.style.background=\'#2ecc80\'" onmouseout="this.style.background=\'#1f9e5c\'">&#10003; Enregistrer</button>'
    + '<button onclick="_cancelAllEdits()" style="background:none;border:1px solid rgba(255,255,255,0.2);color:#8a9bb5;font-family:Arial;font-size:10px;letter-spacing:2px;text-transform:uppercase;padding:10px 28px;cursor:pointer;transition:all 0.2s;" onmouseover="this.style.borderColor=\'rgba(255,255,255,0.5)\';this.style.color=\'#fff\'" onmouseout="this.style.borderColor=\'rgba(255,255,255,0.2)\';this.style.color=\'#8a9bb5\'">&#10006; Annuler</button>'
    + '</div>';

  document.body.appendChild(bar);
}

function saveAllEdits() {
  if (!DB.pageTexts) DB.pageTexts = {};
  Object.keys(_pendingEdits).forEach(function(key) {
    DB.pageTexts[key] = _pendingEdits[key].value;
  });
  saveData(DB);
  _pendingEdits = {};

  // Flash confirmation
  var bar = document.getElementById('inline-edit-bar');
  if (bar) {
    var old = bar.innerHTML;
    bar.innerHTML = '<span style="font-family:Arial;font-size:11px;letter-spacing:2px;color:#2ecc80;margin:auto;">&#10003; Modifications enregistrées</span>';
    setTimeout(function() { _exitEditMode(); }, 1200);
  } else {
    _exitEditMode();
  }
}

function _cancelAllEdits() {
  // Restore original HTML
  Object.keys(_pendingEdits).forEach(function(key) {
    var orig = _pendingEdits[key].el.getAttribute('data-original');
    if (orig !== null) _pendingEdits[key].el.innerHTML = orig;
  });
  _pendingEdits = {};
  _exitEditMode();
}

function _exitEditMode() {
  _editModeActive = false;
  document.body.classList.remove('edit-mode-active');
  _deactivateEditables();
  _removeItemToggles();
  _rerenderItemSections();
  var bar = document.getElementById('inline-edit-bar');
  if (bar) bar.remove();
  var fab = document.getElementById('inline-edit-fab');
  if (fab) { fab.innerHTML = '&#9998; Mode &Eacute;dition'; fab.style.background = '#0d2618'; }
  // Apply saved texts
  applyPageTexts();
}

