function defaultModules() {
  return {
    about:    { enabled: true,  label: 'QUI SOMMES-NOUS',  icon: '&#127968;', page: 'qui-sommes-nous.html' },
    cesaria:  { enabled: true,  label: 'Section Cesária',  icon: '&#127911;', page: 'cesaria.html' },
    artists:  { enabled: true,  label: 'Artistes / Roster',icon: '&#127932;', page: 'artistes.html' },
    music:    { enabled: true,  label: 'Catalogue Musique',icon: '&#127925;', page: 'musique.html' },
    shop:     { enabled: true,  label: 'Boutique / Shop',  icon: '&#128722;', page: 'boutique.html' },
    concerts: { enabled: true,  label: 'Concerts (nav)',   icon: '&#127914;', page: null },
    news:     { enabled: true,  label: 'Actualités',       icon: '&#128240;', page: 'actualites.html' },
    contact:  { enabled: true,  label: 'Contact',          icon: '&#128386;', page: 'contact.html' }
  };
}

function applyModules() {
  if (!DB || !DB.modules) return;
  var def = defaultModules();
  Object.keys(def).forEach(function(k){ if (!DB.modules[k]) DB.modules[k] = def[k]; });
  Object.keys(DB.modules).forEach(function(key) {
    var show = DB.modules[key].enabled;
    document.querySelectorAll('[data-module="'+key+'"]').forEach(function(el){ el.style.display = show ? '' : 'none'; });
    document.querySelectorAll('[data-module-nav="'+key+'"]').forEach(function(el){ el.style.display = show ? '' : 'none'; });
  });
}

function toggleModule(key) {
  if (!isSuperAdmin()) return;
  if (!DB.modules[key]) return;
  DB.modules[key].enabled = !DB.modules[key].enabled;
  saveData(DB);
  applyModules();
  renderModulesAdmin();
}

function renderModulesAdmin() {
  if (!isSuperAdmin()) return;
  var grid = document.getElementById('modules-grid');
  if (!grid) return;
  if (!DB.modules) DB.modules = defaultModules();
  var def = defaultModules();
  Object.keys(def).forEach(function(k){ if (!DB.modules[k]) DB.modules[k] = def[k]; });
  grid.innerHTML = Object.keys(DB.modules).map(function(key) {
    var m = DB.modules[key];
    var on = m.enabled;
    return '<div style="background:var(--card,#0d1f14);border:1px solid '+(on?'rgba(31,158,92,0.4)':'rgba(255,255,255,0.06)')+';padding:20px 24px;border-radius:4px;display:flex;align-items:center;justify-content:space-between;gap:12px;">'
      +'<div>'
        +'<div style="font-size:20px;margin-bottom:6px;">'+m.icon+'</div>'
        +'<div style="font-family:Arial,sans-serif;font-size:12px;letter-spacing:2px;text-transform:uppercase;color:#fff;font-weight:600;">'+m.label+'</div>'
        +'<div style="font-family:Arial,sans-serif;font-size:10px;color:'+(on?'#2ecc80':'#8a9bb5')+';letter-spacing:1px;margin-top:4px;">'+(on?'ACTIF':'DÉSACTIVÉ')+'</div>'
      +'</div>'
      +'<div data-modkey="'+key+'" title="'+(on?'Désactiver':'Activer')+'" style="width:52px;height:28px;border-radius:14px;background:'+(on?'#2ecc80':'rgba(255,255,255,0.1)')+';position:relative;cursor:pointer;transition:background 0.3s;flex-shrink:0;" onclick="toggleModule(this.dataset.modkey)">'
        +'<div style="position:absolute;top:4px;'+(on?'right:4px':'left:4px')+';width:20px;height:20px;border-radius:50%;background:#fff;transition:all 0.3s;"></div>'
      +'</div>'
    +'</div>';
  }).join('');
}


function isAdministrateur() {
  return currentUser && (currentUser.role === 'administrateur' || currentUser.role === 'superadmin');
}
function isEditor() {
  return currentUser && ['superadmin','administrateur','editor'].includes(currentUser.role);
}
function isLecteur() {
  return currentUser && currentUser.role === 'readonly';
}
function canEditContent() {
  return currentUser && ['superadmin','administrateur','editor'].includes(currentUser.role);
}

// Admin nav visibility map
var ADMIN_NAV_ROLES = {
  'dashboard':        ['superadmin','administrateur','editor','readonly'],
  'artists-admin':    ['superadmin','administrateur','editor','readonly'],
  'music-admin':      ['superadmin','administrateur','editor','readonly'],
  'albums-admin':     ['superadmin','administrateur'],
  'news-admin':       ['superadmin','administrateur','editor','readonly'],
  'orders-admin':     ['superadmin','administrateur'],
  'music-categories': ['superadmin','administrateur'],
  'shop-products':    ['superadmin','administrateur'],
  'shop-events':      ['superadmin','administrateur'],
  'payment-links':    ['superadmin','administrateur'],
  'customers-admin':  ['superadmin','administrateur'],
  'users-admin':      ['superadmin','administrateur'],
  'modules-admin':    ['superadmin']
};

// Vérifie si l'utilisateur u est protégé (Super Admin invisible)
function isProtectedUser(u) {
  return u && u.protected === true;
}

// Apply permissions to a page section
function applyPermissions() {
  if (!currentUser) return;
  const sections = ['artists','music','albums','news'];

  sections.forEach(sec => {
    // add buttons
    document.querySelectorAll(`.perm-add-${sec}`).forEach(el => {
      el.style.display = can(sec,'add') ? '' : 'none';
    });
    // delete buttons
    document.querySelectorAll(`.perm-del-${sec}`).forEach(el => {
      el.style.display = can(sec,'delete') ? '' : 'none';
    });
    // full form sections
    document.querySelectorAll(`.perm-form-${sec}`).forEach(el => {
      el.style.display = (can(sec,'add') || can(sec,'edit')) ? '' : 'none';
    });
  });

  // users page (null-safe)
  var _sup  = document.getElementById('users-superadmin-only');
  var _ron  = document.getElementById('users-readonly-notice');
  var _mNav = document.getElementById('admin-modules-nav-item');
  if (isSuperAdmin()) {
    if (_sup)  _sup.style.display  = 'block';
    if (_mNav) _mNav.style.display = '';
    if (_ron)  _ron.style.display  = 'none';
  } else {
    if (_sup)  _sup.style.display  = 'none';
    if (_mNav) _mNav.style.display = 'none';
    if (_ron)  _ron.style.display  = 'block';
  }

  // Update user bar (null-safe)
  var bar = document.getElementById('current-user-bar');
  if (bar) {
    bar.classList.add('active');
    bar.innerHTML = '<strong>' + currentUser.name + '</strong>'
      + ' <span class="cu-role role-' + currentUser.role + '">' + (ROLE_LABELS[currentUser.role]||currentUser.role) + '</span>'
      + ' <button onclick="doLogout()" style="background:none;border:1px solid rgba(255,255,255,0.2);color:var(--gray);padding:4px 12px;font-family:Arial;font-size:9px;letter-spacing:2px;text-transform:uppercase;cursor:pointer;">Déconnexion</button>';
  }

  // Adjust panel margin (null-safe)
  var _ap = document.getElementById('admin-panel');
  if (_ap) _ap.style.marginTop = '36px';

  // ── Filter admin nav items by role ──
  document.querySelectorAll('.admin-nav-item[onclick]').forEach(function(el) {
    var m = (el.getAttribute('onclick')||'').match(/showAdminPage\('([^']+)'\)/);
    if (!m) return;
    var allowed = ADMIN_NAV_ROLES[m[1]] || ['superadmin'];
    el.style.display = (currentUser && allowed.includes(currentUser.role)) ? '' : 'none';
  });

  // ── Show inline edit button if user can edit content ──
  initInlineEditBtn();
}

// ========================
// IMAGES
// ========================
function getImg(key) { return IMG[key] || null; }

function artistImg(artist) {
  if (artist.photo && artist.photo.startsWith('data:')) return artist.photo;
  const map = {"IMG_ELIDA":"elida","IMG_CEUZANY":"ceuzany","IMG_JENIFER":"jenifer","IMG_NEUZA":"neuza","IMG_FABIO":"fabio","IMG_LUCIBELA":"cesaria","IMG_CESARIA":"cesaria"};
  if (artist.photo && map[artist.photo]) return getImg(map[artist.photo]);
  return null;
}

// ========================
// PUBLIC RENDERING
// ========================
function renderArtists() {
  const grid = document.getElementById('artists-grid');
  if (!grid) return;
  const editMode = (typeof _editModeActive !== 'undefined') && _editModeActive
    && (typeof isEditor === 'function') && isEditor();
  grid.innerHTML = DB.artists.map(function(a) {
    const active = (typeof isItemActive === 'function') ? isItemActive('artist', a.id) : true;
    if (!active && !editMode) return '';
    const img = artistImg(a);
    const photoEl = img
      ? '<img src="' + img + '" alt="' + esc(a.name) + '" loading="lazy">'
      : '<div class="artist-no-photo">&#9834;</div>';
    const inactiveBadge = !active ? '<div class="item-inactive-badge">DÉSACTIVÉ</div>' : '';
    const toggleHtml = editMode ? buildItemToggle('artist', a.id, active) : '';
    const inactiveClass = !active ? ' item-card-inactive' : '';
    const clickAction = a.pageLink ? 'window.location.href=\'' + a.pageLink + '\'' : 'openArtistPage(' + a.id + ')';
    return '<div class="artist-card' + inactiveClass + '" data-item-type="artist" data-item-id="' + a.id + '" onclick="' + clickAction + '" style="cursor:pointer;">'
      + photoEl
      + '<div class="artist-overlay">'
      + '<div class="artist-origin">' + esc(a.origin || '') + '</div>'
      + (a.style ? '<div class="artist-style">' + esc(a.style) + '</div>' : '')
      + '<div class="artist-name">' + esc(a.name) + '</div>'
      + '<div class="artist-bio">' + esc(a.bioShort || '') + '</div>'
      + '<button class="artist-more" data-i18n="artist_more">Découvrir →</button>'
      + '</div>'
      + inactiveBadge
      + toggleHtml
      + '</div>';
  }).join('');
  if (editMode && typeof _attachItemToggles === 'function') _attachItemToggles();
}


function openArtistModal(id) {
  const a = DB.artists.find(x => x.id === id);
  if (!a) return;
  const img = artistImg(a);
  const photoDiv = document.getElementById('modal-photo-wrap');
  const imgEl    = document.getElementById('modal-img');
  if (img) {
    imgEl.src = img; imgEl.style.display = 'block';
    if (photoDiv) photoDiv.style.display = 'block';
  } else {
    imgEl.style.display = 'none';
    if (photoDiv) photoDiv.style.display = 'none';
  }
  const el = n => document.getElementById(n);
  if (el('modal-name'))   el('modal-name').textContent   = a.name;
  if (el('modal-origin')) el('modal-origin').textContent = a.origin || '';
  if (el('modal-style'))  el('modal-style').textContent  = a.style  || '';
  if (el('modal-bio'))    el('modal-bio').textContent    = a.bioLong || a.bioShort || '';

  const socials = [
    a.instagram && {url: a.instagram, label: 'Instagram'},
    a.facebook  && {url: a.facebook,  label: 'Facebook'},
    a.youtube   && {url: a.youtube,   label: 'YouTube'},
    a.spotify   && {url: a.spotify,   label: 'Spotify'},
  ].filter(Boolean);

  if (el('modal-social')) {
    el('modal-social').innerHTML = socials.map(s =>
      `<a class="modal-social-btn" href="${s.url}" target="_blank" rel="noopener">${s.label}</a>`
    ).join('');
  }
  const ov = document.getElementById('artist-modal');
  if (ov) { ov.classList.add('active'); document.body.style.overflow = 'hidden'; }
}


function closeModal() {
  document.getElementById('artist-modal').classList.remove('active');
  document.body.style.overflow = '';
}

var _am=document.getElementById('artist-modal'); if(_am) _am.addEventListener('click', e => {
  if (e.target === document.getElementById('artist-modal')) closeModal();
});

function renderTracks() {
  const list = document.getElementById('tracks-list');
  if (DB.tracks.length === 0) {
    list.innerHTML = '<div style="color:var(--gray);font-family:Arial;font-size:12px;letter-spacing:2px;text-transform:uppercase;padding:40px 0;text-align:center;">Catalogue en cours de constitution</div>';
    return;
  }
  list.innerHTML = DB.tracks.map((t, i) => `
    <div class="music-track" onclick="playTrack(${i})">
      <div class="track-num">${String(i+1).padStart(2,'0')}</div>
      <div class="track-cover">${t.cover ? `<img src="${t.cover}" alt="">` : `<div style="width:100%;height:100%;background:var(--blue);"></div>`}</div>
      <button class="track-play-btn"><svg viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg></button>
      <div class="track-info">
        <div class="track-title">${esc(t.title)}</div>
        <div class="track-artist">${esc(t.artist)}${t.album?' — '+esc(t.album):''}</div>
      </div>
      <div class="track-duration">${t.duration||'—'}</div>
    </div>`).join('');
}

function renderNews() {
  const grid = document.getElementById('news-grid');
  if (!grid) return;

  const lang = (typeof currentLang !== 'undefined' && currentLang) || 'pt';
  const editMode = (typeof _editModeActive !== 'undefined') && _editModeActive
    && (typeof isEditor === 'function') && isEditor();

  // Source de vérité multilingue (toujours à jour)
  const defaults = defaultNews();
  const defaultsMap = {};
  defaults.forEach(function(d){ defaultsMap[d.id] = d; });

  const allNews = [...DB.news].reverse();
  const items = editMode ? allNews : allNews.filter(function(n) {
    return (typeof isItemActive === 'function') ? isItemActive('news', n.id) : true;
  }).slice(0,6);

  grid.innerHTML = items.map(function(n) {
    const active = (typeof isItemActive === 'function') ? isItemActive('news', n.id) : true;
    // Fusionner avec la version multilingue des defaults si disponible
    const def = defaultsMap[n.id];
    const titleObj   = (def && typeof def.title   === 'object') ? def.title   : (typeof n.title   === 'object' ? n.title   : null);
    const excerptObj = (def && typeof def.excerpt === 'object') ? def.excerpt : (typeof n.excerpt === 'object' ? n.excerpt : null);

    const title   = titleObj   ? (titleObj[lang]   || titleObj.pt   || titleObj.fr   || n.title   || '') : (n.title   || '');
    const excerpt = excerptObj ? (excerptObj[lang] || excerptObj.pt || excerptObj.fr || n.excerpt || '') : (n.excerpt || '');

    const inactiveBadge = !active ? '<div class="item-inactive-badge">DÉSACTIVÉ</div>' : '';
    const toggleHtml = editMode ? buildItemToggle('news', n.id, active) : '';
    const inactiveClass = !active ? ' item-card-inactive' : '';

    return '<div class="news-card' + inactiveClass + '" data-item-type="news" data-item-id="' + n.id + '" style="position:relative;overflow:visible;">'
      + (n.img
          ? '<img class="news-card-img" src="' + n.img + '" alt="' + esc(title) + '">'
          : '<div style="height:220px;background:linear-gradient(135deg,var(--navy2),var(--blue));display:flex;align-items:center;justify-content:center;font-size:40px;">&#128240;</div>')
      + '<div class="news-card-body">'
      +   '<div class="news-date">' + fmtDate(n.date) + '</div>'
      +   '<div class="news-title">' + esc(title) + '</div>'
      +   '<div class="news-excerpt">' + esc(excerpt) + '</div>'
      +   '<span class="news-artist-tag">' + esc(n.artist || '') + '</span>'
      + '</div>'
      + inactiveBadge
      + toggleHtml
      + '</div>';
  }).join('');
  if (editMode && typeof _attachItemToggles === 'function') _attachItemToggles();
}

function fmtDate(d) {
  if (!d) return '';
  const [y,m,day] = d.split('-');
  const months = (typeof T === 'function' ? T('months') : 'Jan,Fév,Mar,Avr,Mai,Jun,Jul,Aoû,Sep,Oct,Nov,Déc').split(',');
  return `${day} ${months[parseInt(m)-1]} ${y}`;
}

// ========================
// AUDIO PLAYER
// ========================
let currentTrack = -1, isPlaying = false;
const audio = document.getElementById('audio-el');

audio.addEventListener('timeupdate', () => {
  if (!audio.duration) return;
  document.getElementById('bar-fill').style.width = (audio.currentTime/audio.duration*100)+'%';
  document.getElementById('bar-current').textContent = fmtTime(audio.currentTime);
});
audio.addEventListener('loadedmetadata', () => { document.getElementById('bar-total').textContent = fmtTime(audio.duration); });
audio.addEventListener('ended', nextTrack);

function fmtTime(s) { return Math.floor(s/60)+':'+String(Math.floor(s%60)).padStart(2,'0'); }

function playTrack(i) {
  const t = DB.tracks[i]; if (!t) return;
  currentTrack = i;
  if (t.audioData) { audio.src = t.audioData; audio.play(); isPlaying = true; }
  else if (t.url) { window.open(t.url,'_blank'); return; }
  document.getElementById('bar-title').textContent = t.title;
  document.getElementById('bar-artist').textContent = t.artist;
  document.getElementById('player-bar').classList.add('active');
  updatePlayIcon();
}

function togglePlay() {
  if (audio.paused) { audio.play(); isPlaying=true; } else { audio.pause(); isPlaying=false; }
  updatePlayIcon();
}

function updatePlayIcon() {
  document.getElementById('play-icon').innerHTML = isPlaying
    ? '<path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/>'
    : '<path d="M8 5v14l11-7z"/>';
}

function prevTrack() { if (currentTrack>0) playTrack(currentTrack-1); }
function nextTrack() { if (currentTrack<DB.tracks.length-1) playTrack(currentTrack+1); }
function seekTo(e) { audio.currentTime = (e.offsetX/e.currentTarget.offsetWidth)*audio.duration; }

// ========================
// CONTACT
// ========================
function sendContact() {
  const name=document.getElementById('contact-name')?.value?.trim();
  const email=document.getElementById('contact-email')?.value?.trim();
  const msg=document.getElementById('contact-message')?.value?.trim();
  if(!name||!email||!msg){alert(T('contact_fill_all')||'Veuillez remplir tous les champs.');return;}
  if(!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)){alert('Email invalide.');return;}
  const subject=encodeURIComponent('Contact HARMONIA — '+name);
  const body=encodeURIComponent('De: '+name+'\nEmail: '+email+'\n\n'+msg);
  window.open('mailto:harmonia.producao@gmail.com?subject='+subject+'&body='+body,'_blank');
  document.getElementById('contact-name').value='';
  document.getElementById('contact-email').value='';
  document.getElementById('contact-message').value='';
  const btn=document.querySelector('.contact-submit');
  if(btn){const orig=btn.textContent;btn.textContent='✓ Message ouvert';btn.disabled=true;setTimeout(()=>{btn.textContent=orig;btn.disabled=false;},3000);}
}

// ========================
// ADMIN LOGIN / LOGOUT
// ========================
function openAdmin(e) {
  if (e) e.preventDefault();
  var overlay = document.getElementById('admin-overlay');
  if (!overlay) return;
  overlay.classList.add('active');
  overlay.classList.remove('collapsed');
  _updateDrawerTab(false);
}

function closeAdmin(e) {
  e && e.preventDefault();
  var overlay = document.getElementById('admin-overlay');
  if (!overlay) return;
  if (currentUser) {
    // Connecté : replier (pas fermer)
    overlay.classList.add('collapsed');
    _updateDrawerTab(true);
  } else {
    // Non connecté : fermer complètement
    overlay.classList.remove('active');
    _updateDrawerTab(false, true);
  }
}

// ── Drawer tab helpers ──
function _updateDrawerTab(collapsed, hidden) {
  var tab = document.getElementById('admin-drawer-tab');
  if (!tab) return;
  if (hidden) {
    tab.classList.remove('visible');
    tab.style.left = '-52px';
    return;
  }
  tab.classList.add('visible');
  tab.style.left = collapsed ? '44px' : '360px';
  tab.innerHTML = collapsed ? '&#10095;' : '&#10094;';
}

function _toggleDrawer() {
  var overlay = document.getElementById('admin-overlay');
  if (!overlay || !overlay.classList.contains('active')) return;
  var isCollapsed = overlay.classList.contains('collapsed');
  if (isCollapsed) {
    overlay.classList.remove('collapsed');
    _updateDrawerTab(false);
  } else {
    overlay.classList.add('collapsed');
    _updateDrawerTab(true);
  }
}

function _moveUserBarToDrawer() {
  var bar = document.getElementById('current-user-bar');
  var overlay = document.getElementById('admin-overlay');
  if (!bar || !overlay || overlay.firstChild === bar) return;
  overlay.insertBefore(bar, overlay.firstChild);
}

function _injectDrawerTab() {
  if (document.getElementById('admin-drawer-tab')) return;
  var tab = document.createElement('button');
  tab.id = 'admin-drawer-tab';
  tab.setAttribute('aria-label', 'Afficher/masquer le panneau');
  tab.onclick = _toggleDrawer;
  document.body.appendChild(tab);
}

function openAdminDrawer() {
  // Sur admin.html : le panel est déjà affiché en plein écran
  if (typeof window._adminPageShowPanel === 'function') {
    window._adminPageShowPanel();
    return;
  }
  var overlay = document.getElementById('admin-overlay');
  if (!overlay) return;
  overlay.classList.add('active');
  overlay.classList.remove('collapsed');
  _updateDrawerTab(false);
}

function _toggleAuthMode(mode) {
  var loginForm = document.getElementById('auth-login-form');
  var regForm   = document.getElementById('auth-register-form');
  var loginTab  = document.getElementById('auth-tab-login');
  var regTab    = document.getElementById('auth-tab-register');
  var errEl     = document.getElementById('login-err');
  var regErrEl  = document.getElementById('register-err');
  if (errEl) errEl.style.display = 'none';
  if (regErrEl) regErrEl.style.display = 'none';
  if (mode === 'register') {
    if (loginForm) loginForm.style.display = 'none';
    if (regForm)   regForm.style.display   = 'block';
    if (loginTab)  loginTab.classList.remove('auth-tab-active');
    if (regTab)    regTab.classList.add('auth-tab-active');
  } else {
    if (loginForm) loginForm.style.display = 'block';
    if (regForm)   regForm.style.display   = 'none';
    if (loginTab)  loginTab.classList.add('auth-tab-active');
    if (regTab)    regTab.classList.remove('auth-tab-active');
  }
}

function doLogin() {
  var emailEl = document.getElementById('login-email');
  var passEl  = document.getElementById('login-pass');
  if (!emailEl || !passEl) return;
  var email = emailEl.value.trim().toLowerCase();
  var pass  = passEl.value;
  var errEl = document.getElementById('login-err');
  var user = DB.users.find(function(x) {
    return (x.email && x.email.toLowerCase() === email) && x.pass === pass;
  });
  if (!user) {
    // Backward compat: also try matching by login field
    user = DB.users.find(function(x) { return x.login && x.login.toLowerCase() === email && x.pass === pass; });
  }
  if (user) {
    currentUser = user;
    try {
      sessionStorage.setItem('harmonia_user', JSON.stringify({
        id: user.id, login: user.login, email: user.email,
        name: user.name, role: user.role, permissions: user.permissions
      }));
    } catch(e) {}

    var isMembre = (user.role === 'membre');

    if (!isMembre) {
      // Admin/superadmin → redirection vers admin.html
      // Si déjà sur admin.html, afficher le panel directement
      if (typeof window._adminPageShowPanel === 'function') {
        window._adminPageShowPanel();
      } else {
        window.location.href = 'admin.html';
        return; // stopper l'exécution, la page va changer
      }
    } else {
      // Membre : fermer le formulaire de login, rester sur la page
      var _loginBox = document.getElementById('admin-login');
      if (_loginBox) _loginBox.style.display = 'none';
      var _ao2 = document.getElementById('admin-overlay');
      if (_ao2) { _ao2.classList.remove('active'); _ao2.classList.remove('collapsed'); }
      // Achat en attente (déclenché via requireAuthForPurchase)
      if (_pendingPurchaseCallback) {
        var _pcb = _pendingPurchaseCallback;
        _pendingPurchaseCallback = null;
        setTimeout(_pcb, 250);
      }
    }

    applyPermissions();
    applyNavPermissions();
    updateNavConnectBtn();
    if (errEl) errEl.style.display = 'none';
    _clearPurchaseNotice();
    document.dispatchEvent(new CustomEvent('harmonia:login', { detail: { role: user.role } }));
  } else {
    if (errEl) errEl.style.display = 'block';
  }
}

function doRegister() {
  var nameEl    = document.getElementById('reg-name');
  var emailEl   = document.getElementById('reg-email');
  var passEl    = document.getElementById('reg-pass');
  var pass2El   = document.getElementById('reg-pass2');
  var errEl     = document.getElementById('register-err');
  if (!nameEl || !emailEl || !passEl || !pass2El || !errEl) return;
  var name  = nameEl.value.trim();
  var email = emailEl.value.trim().toLowerCase();
  var pass  = passEl.value;
  var pass2 = pass2El.value;
  var re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!name) { errEl.textContent = 'Nom requis.'; errEl.style.display = 'block'; return; }
  if (!re.test(email)) { errEl.textContent = 'Adresse email invalide.'; errEl.style.display = 'block'; return; }
  if (pass.length < 6) { errEl.textContent = 'Mot de passe trop court (6 caractères min).'; errEl.style.display = 'block'; return; }
  if (pass !== pass2) { errEl.textContent = 'Les mots de passe ne correspondent pas.'; errEl.style.display = 'block'; return; }
  if (DB.users.find(function(u) { return u.email && u.email.toLowerCase() === email; })) {
    errEl.textContent = 'Cette adresse email est déjà utilisée.'; errEl.style.display = 'block'; return;
  }
  var newUser = {
    id: Date.now(),
    login: email,
    email: email,
    pass: pass,
    name: name,
    role: 'membre',
    permissions: ROLE_TEMPLATES.membre,
    createdAt: new Date().toISOString().split('T')[0]
  };
  DB.users.push(newUser);
  saveData(DB);
  // Auto-login after registration
  currentUser = newUser;
  try {
    sessionStorage.setItem('harmonia_user', JSON.stringify({
      id: newUser.id, login: newUser.login, email: newUser.email,
      name: newUser.name, role: newUser.role, permissions: newUser.permissions
    }));
  } catch(e) {}
  document.getElementById('admin-login').style.display = 'none';
  var _ao3 = document.getElementById('admin-overlay');
  if (_ao3) { _ao3.classList.remove('active'); _ao3.classList.remove('collapsed'); }
  applyPermissions();
  applyNavPermissions();
  updateNavConnectBtn();
  errEl.style.display = 'none';
  _clearPurchaseNotice();
  if (_pendingPurchaseCallback) {
    var _pcb2 = _pendingPurchaseCallback;
    _pendingPurchaseCallback = null;
    setTimeout(_pcb2, 250);
  }
}

function doLogout() {
  currentUser = null;
  try { sessionStorage.removeItem('harmonia_user'); } catch(e) {}
  // Fermer le menu mobile si ouvert
  if (typeof window.__closeMenu === 'function') window.__closeMenu();
  var _al = document.getElementById('admin-login');     if (_al) _al.style.display = 'flex';
  var _ap = document.getElementById('admin-panel');     if (_ap) _ap.classList.remove('active');
  var _lu = document.getElementById('login-email');     if (_lu) _lu.value = '';
  var _lp = document.getElementById('login-pass');      if (_lp) _lp.value = '';
  var _le = document.getElementById('login-err');       if (_le) _le.style.display = 'none';
  var _rn = document.getElementById('reg-name');        if (_rn) _rn.value = '';
  var _re = document.getElementById('reg-email');       if (_re) _re.value = '';
  var _rp = document.getElementById('reg-pass');        if (_rp) _rp.value = '';
  var _r2 = document.getElementById('reg-pass2');       if (_r2) _r2.value = '';
  var _rer= document.getElementById('register-err');    if (_rer) _rer.style.display = 'none';
  _toggleAuthMode('login');
  var _cb = document.getElementById('current-user-bar'); if (_cb) _cb.classList.remove('active');
  if (typeof _editModeActive !== 'undefined' && _editModeActive) {
    _editModeActive = false;
    if (typeof _rerenderItemSections === 'function') _rerenderItemSections();
    var fab = document.getElementById('inline-edit-fab'); if (fab) fab.style.display = 'none';
  }
  // Fermer le drawer complètement
  var _ao = document.getElementById('admin-overlay');
  if (_ao) { _ao.classList.remove('active'); _ao.classList.remove('collapsed'); }
  _updateDrawerTab(false, true);
  updateNavConnectBtn();
  // Sur admin.html : retour login, sinon event
  if (typeof window._adminPageShowLogin === 'function') {
    window._adminPageShowLogin();
  }
  document.dispatchEvent(new CustomEvent('harmonia:logout'));
}

// Hide nav items user cannot access
function applyNavPermissions() {
  const map = {
    'artists-admin': 'artists',
    'music-admin': 'music',
    'albums-admin': 'albums',
    'news-admin': 'news',
    'users-admin': 'users'
  };
  document.querySelectorAll('.admin-nav-item').forEach(item => {
    const onclick = item.getAttribute('onclick') || '';
    const match = onclick.match(/showAdminPage\('(.+?)'\)/);
    if (!match) return;
    const page = match[1];
    const section = map[page];
    if (!section) return;
    if (section === 'users') {
      item.style.display = isSuperAdmin() ? '' : 'none';
    } else {
      item.style.display = can(section,'view') ? '' : 'none';
    }
  });
}

function showAdminPage(id) {
  document.querySelectorAll('.admin-page').forEach(p => p.classList.remove('active'));
  document.getElementById('page-'+id).classList.add('active');
  document.querySelectorAll('.admin-nav-item').forEach(n => n.classList.remove('active'));
  if (event && event.currentTarget) event.currentTarget.classList.add('active');
  if (id === 'orders-admin') { refreshAdminOrders(); }
  if (id === 'shop-products') { refreshProdArtistSelect(); renderProds(); }
  if (id === 'music-categories') { renderMusicCategoriesList(); }
  if (id === 'shop-events') { refreshEvtArtistSelect(); renderEvts(); }
  if (id === 'payment-links') { refreshPLinkItems(); renderPLinks(); }
  if (id === 'customers-admin') { renderCustomers(); }
  if (id === 'modules-admin') { renderModulesAdmin(); }
}

function updateStats() {
  document.getElementById('stat-artists').textContent = DB.artists.length;
  document.getElementById('stat-tracks').textContent = DB.tracks.length;
  document.getElementById('stat-albums').textContent = DB.albums.length;
  document.getElementById('stat-news').textContent = DB.news.length;
}

// ========================
// RBAC — USER MANAGEMENT
// ========================
function applyRoleTemplate() {
  const role = document.getElementById('u-role').value;
  const tpl = ROLE_TEMPLATES[role];
  if (!tpl) return;
  document.querySelectorAll('.perm-chk').forEach(chk => {
    const sec = chk.dataset.section;
    const act = chk.dataset.action;
    if (tpl[sec]) chk.checked = !!tpl[sec][act];
  });
}

function getPermissionsFromForm() {
  const sections = ['artists','music','albums','news'];
  const actions  = ['view','add','edit','delete'];
  const p = {};
  sections.forEach(s => {
    p[s] = {};
    actions.forEach(a => {
      const chk = document.querySelector(`.perm-chk[data-section="${s}"][data-action="${a}"]`);
      p[s][a] = chk ? chk.checked : false;
    });
  });
  p.users = {view:false, add:false, edit:false, delete:false};
  return p;
}

function saveUser() {
  var _callerRole = currentUser ? currentUser.role : '';
  var _isSA = (_callerRole === 'superadmin');
  var _isAD = (_callerRole === 'administrateur');
  if (!_isSA && !_isAD) return;

  const login = document.getElementById('u-login') ? document.getElementById('u-login').value.trim() : '';
  const email = document.getElementById('u-email') ? document.getElementById('u-email').value.trim().toLowerCase() : '';
  const pass  = document.getElementById('u-pass').value.trim();
  const name  = document.getElementById('u-name').value.trim();
  const role  = document.getElementById('u-role').value;
  const perms = getPermissionsFromForm();
  const reEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

  if (window._editUserId !== undefined && window._editUserId !== null) {
    // MODIFICATION
    if (!name) { alert('Nom requis.'); return; }
    if (email && !reEmail.test(email)) { alert('Email invalide.'); return; }
    const idx = DB.users.findIndex(u => u.id === window._editUserId);
    if (idx !== -1) {
      var target = DB.users[idx];
      // Administrateur ne peut pas modifier un compte protégé (superadmin)
      if (!_isSA && target.protected) { alert('Ce compte est protégé — seul le Webmaster peut le modifier.'); return; }
      // Administrateur ne peut pas élever au rang superadmin
      if (!_isSA && role === 'superadmin') { alert('Vous ne pouvez pas attribuer le rôle superadmin.'); return; }
      if (login) DB.users[idx].login = login;
      if (email) DB.users[idx].email = email;
      DB.users[idx].name  = name;
      DB.users[idx].role  = role;
      DB.users[idx].permissions = perms;
      if (pass) DB.users[idx].pass = pass;
    }
    window._editUserId = null;
    const btn = document.querySelector('#page-users-admin .admin-btn-sm[onclick="saveUser()"]');
    if (btn) btn.textContent = "Créer l'utilisateur";
  } else {
    // CRÉATION
    if (!email || !pass || !name) { alert('Email, mot de passe et nom sont requis.'); return; }
    if (!reEmail.test(email)) { alert('Email invalide.'); return; }
    if (DB.users.find(u => u.email && u.email.toLowerCase() === email)) { alert('Cet email existe déjà.'); return; }
    // Administrateur ne peut pas créer un superadmin
    if (!_isSA && role === 'superadmin') { alert('Vous ne pouvez pas attribuer le rôle superadmin.'); return; }
    const user = {
      id: Date.now(),
      login: login || email,
      email,
      pass, name, role,
      permissions: perms,
      createdAt: new Date().toISOString().split('T')[0]
    };
    DB.users.push(user);
  }
  saveData(DB);
  renderUsersAdminList();
  updateStats();
  resetUserForm();
  showSuccess('users-success');
}

function resetUserForm() {
  ['u-login','u-email','u-pass','u-name'].forEach(id => { var el = document.getElementById(id); if (el) el.value = ''; });
  document.getElementById('u-role').value = 'custom';
  document.querySelectorAll('.perm-chk').forEach(c => {
    c.checked = c.dataset.action === 'view';
  });
}

function deleteUser(id) {
  if (!isSuperAdmin() && !isAdministrateur()) return;
  var _du = (DB.users||[]).find(function(x){ return x.id === id; });
  if (!_du) return;
  if (isProtectedUser(_du)) {
    var _dp = prompt('Compte protégé — mot de passe administrateur requis :');
    if (_dp !== 'Music7') { alert('Mot de passe incorrect.'); return; }
  }
  if (!confirm('Supprimer cet utilisateur ?')) return;
  DB.users = DB.users.filter(function(x){ return x.id !== id; });
  saveData(DB);
  renderUsersAdminList();
}

function renderUsersAdminList() {
  const el = document.getElementById('users-admin-list');
  if (!el) return;
  // Filtrer les utilisateurs : un non-superadmin ne voit pas les comptes protégés
  const visibleUsers = DB.users.filter(u => {
    if (isProtectedUser(u) && !isSuperAdmin()) return false;
    return true;
  });
  el.innerHTML = visibleUsers.map(u => {
    const sections = ['artists','music','albums','news'];
    const permSummary = sections.map(s => {
      const p = u.permissions[s] || {};
      const actions = [];
      if (p.view) actions.push('V');
      if (p.add) actions.push('A');
      if (p.edit) actions.push('M');
      if (p.delete) actions.push('S');
      return `<span style="font-size:9px;color:var(--gray);letter-spacing:1px;">${s.charAt(0).toUpperCase()+s.slice(1)}: <span style="color:var(--accent2);">${actions.join('·')||'—'}</span></span>`;
    }).join('&nbsp;&nbsp;');

    const canDel = (isSuperAdmin() || isAdministrateur()) && !isProtectedUser(u);
    const canEdit = isSuperAdmin() || (isAdministrateur() && !isProtectedUser(u));
    return `
    <div class="admin-list-item" style="flex-direction:column;align-items:flex-start;gap:10px;">
      <div style="display:flex;width:100%;align-items:center;">
        <div class="admin-item-info">
          <div class="admin-item-title">
            ${u.name}
            <span class="role-badge role-${u.role}">${ROLE_LABELS[u.role]||u.role}</span>
          </div>
          <div class="admin-item-meta">${u.email || u.login} · Créé le ${u.createdAt}</div>
        </div>
        <div class="admin-item-actions">
          ${canEdit ? `<button class="admin-btn-sm" onclick="editUser(${u.id})" style="margin-right:6px;">Modifier</button>` : ''}
          ${canDel ? `<button class="admin-btn-del" onclick="deleteUser(${u.id})">Supprimer</button>` : '<span style="font-size:9px;color:var(--gray);letter-spacing:1px;">Protégé</span>'}
        </div>
      </div>
      <div style="display:flex;gap:16px;flex-wrap:wrap;padding-left:0;">${permSummary}</div>
    </div>`;
  }).join('');
}

