// ========================
// ADMIN — Edit functions
// ========================
var currentEditArtistId = null;
var currentEditAlbumId = null;
var currentEditNewsId = null;
var currentEditTrackId = null;

function editArtist(id) {
  const a = DB.artists.find(x => x.id === id);
  if (!a) return;
  document.getElementById('a-name').value = a.name || '';
  document.getElementById('a-origin').value = a.origin || '';
  document.getElementById('a-bio-short').value = a.bioShort || '';
  document.getElementById('a-bio-long').value = a.bioLong || '';
  document.getElementById('a-insta').value = a.instagram || '';
  document.getElementById('a-spotify').value = a.spotify || '';
  currentEditArtistId = id;
  showAdminPage('artists-admin');
  document.getElementById('a-name').scrollIntoView({behavior:'smooth'});
}

function editTrack(id) {
  const t = DB.tracks.find(x => x.id === id);
  if (!t) return;
  document.getElementById('t-title').value = t.title || '';
  const tArtist = document.getElementById('t-artist');
  if (tArtist) { for(let i=0;i<tArtist.options.length;i++){if(tArtist.options[i].value===t.artist){tArtist.selectedIndex=i;break;}} }
  document.getElementById('t-album').value = t.album || '';
  document.getElementById('t-duration').value = t.duration || '';
  document.getElementById('t-url').value = t.url || '';
  var ts = document.getElementById('track-style'); if(ts) ts.value = t.style||'';
  var tc = document.getElementById('track-category'); if(tc) tc.value = t.category||'traditional';
  currentEditTrackId = id;
  showAdminPage('music-admin');
  document.getElementById('t-title').scrollIntoView({behavior:'smooth'});
}

function editAlbum(id) {
  const a = DB.albums.find(x => x.id === id);
  if (!a) return;
  document.getElementById('al-title').value = a.title || '';
  const alArtist = document.getElementById('al-artist');
  if (alArtist) { for(let i=0;i<alArtist.options.length;i++){if(alArtist.options[i].value===a.artist){alArtist.selectedIndex=i;break;}} }
  document.getElementById('al-year').value = a.year || '';
  document.getElementById('al-label').value = a.label || '';
  document.getElementById('al-desc').value = a.desc || '';
  currentEditAlbumId = id;
  showAdminPage('albums-admin');
  document.getElementById('al-title').scrollIntoView({behavior:'smooth'});
}

function editNews(id) {
  const n = DB.news.find(x => x.id === id);
  if (!n) return;
  document.getElementById('n-title').value = n.title || '';
  const nArtist = document.getElementById('n-artist');
  if (nArtist) { for(let i=0;i<nArtist.options.length;i++){if(nArtist.options[i].value===n.artist){nArtist.selectedIndex=i;break;}} }
  document.getElementById('n-date').value = n.date || '';
  document.getElementById('n-excerpt').value = n.excerpt || '';
  document.getElementById('n-content').value = n.content || '';
  currentEditNewsId = id;
  showAdminPage('news-admin');
  document.getElementById('n-title').scrollIntoView({behavior:'smooth'});
}

function deleteOrder(orderId) {
  if (!confirm('Supprimer cette commande ?')) return;
  try {
    var orders = JSON.parse(localStorage.getItem(ORDERS_KEY) || '[]');
    orders = orders.filter(o => o.id !== orderId);
    localStorage.setItem(ORDERS_KEY, JSON.stringify(orders));
    refreshAdminOrders();
  } catch(e) {}
}

function refreshAdminLists() {
  populateArtistSelects();
  renderArtistsAdminList();
  renderMusicAdminList();
  renderAlbumsAdminList();
  renderNewsAdminList();
  renderUsersAdminList();
  document.getElementById('n-date').value = new Date().toISOString().split('T')[0];
}

function showSuccess(id) {
  const el = document.getElementById(id);
  el.classList.add('show');
  setTimeout(() => el.classList.remove('show'), 3000);
}

