function loadCart() {
  try { return JSON.parse(sessionStorage.getItem(CART_KEY)) || []; }
  catch(e) { return []; }
}
function saveCart(cart) {
  sessionStorage.setItem(CART_KEY, JSON.stringify(cart));
  updateCartBadge();
  renderMiniCart();
}
function updateCartBadge() {
  const cart = loadCart();
  const total = cart.reduce((s,i) => s + i.qty, 0);
  const badge = document.getElementById('cart-badge');
  if (!badge) return;
  badge.textContent = total;
  badge.classList.toggle('visible', total > 0);
  const hcount = document.getElementById('cart-header-count');
  if (hcount) hcount.textContent = total === 0 ? '0 article' : total + ' article' + (total > 1 ? 's' : '');
}

// ── Auth-gate for purchase ─────────────────────────────────────────────────
var _pendingPurchaseCallback = null;

function requireAuthForPurchase(callback) {
  if (currentUser) { callback(); return; }
  _pendingPurchaseCallback = callback;
  _toggleAuthMode('login');
  // Affiche un bandeau "connexion requise pour acheter"
  var notice = document.getElementById('login-purchase-notice');
  if (!notice) {
    var box = document.querySelector('.admin-login-box');
    if (box) {
      notice = document.createElement('div');
      notice.id = 'login-purchase-notice';
      notice.style.cssText = 'background:rgba(31,158,92,0.08);border:1px solid rgba(31,158,92,0.25);color:var(--accent2);font-family:Arial,sans-serif;font-size:10px;letter-spacing:2px;text-transform:uppercase;padding:10px 16px;margin-bottom:20px;text-align:center;';
      notice.textContent = 'Connectez-vous pour finaliser votre achat';
      box.insertBefore(notice, box.firstChild);
    }
  } else {
    notice.style.display = 'block';
  }
  var overlay = document.getElementById('admin-overlay');
  if (overlay) { overlay.classList.add('active'); overlay.classList.remove('collapsed'); }
}

function _clearPurchaseNotice() {
  var notice = document.getElementById('login-purchase-notice');
  if (notice) notice.style.display = 'none';
}

function addToCart(id, type, name, artist, price, imgKey, extra) {
  // Ajout libre — auth requise uniquement au checkout / paiement Stripe
  _doAddToCart(id, type, name, artist, price, imgKey, extra);
}

function _doAddToCart(id, type, name, artist, price, imgKey, extra) {
  const cart = loadCart();
  const key = String(id)+'|'+type+(extra?'|'+extra:'');
  const existing = cart.find(i => String(i.id)+'|'+i.type+(i.extra?'|'+i.extra:'') === key);
  if (existing) { existing.qty++; }
  else { cart.push({id, type, name, artist, price, imgKey, qty:1, extra: extra||''}); }
  saveCart(cart);
  openMiniCart();
  showCartToast(name);
  const btn = document.querySelector('[data-cart-id="'+id+'-'+type+(extra?'-'+extra:'')+'"]');
  if (btn) { const orig=btn.textContent; btn.textContent='✓ Ajouté'; btn.style.background='var(--accent2)'; btn.style.color='var(--dark)'; setTimeout(()=>{btn.textContent=orig;btn.style.background='';btn.style.color='';},1500); }
}

function showCartToast(productName) {
  var toast = document.getElementById('cart-toast');
  if (!toast) {
    toast = document.createElement('div');
    toast.id = 'cart-toast';
    document.body.appendChild(toast);
  }
  toast.innerHTML = '<span class="cart-toast-label">PANIER</span><span class="cart-toast-name">' + (productName || '') + '</span>';
  toast.classList.remove('cart-toast-visible', 'cart-toast-hide');
  void toast.offsetWidth; // force reflow pour relancer l'animation
  toast.classList.add('cart-toast-visible');
  clearTimeout(toast._hideTimer);
  toast._hideTimer = setTimeout(function() {
    toast.classList.add('cart-toast-hide');
  }, 3000);
}

function removeFromCart(idx) {
  const cart = loadCart(); cart.splice(idx, 1); saveCart(cart); renderCart();
}
function changeQty(idx, delta) {
  const cart = loadCart(); cart[idx].qty = Math.max(1, cart[idx].qty + delta); saveCart(cart); renderCart();
}
function cartTotal() { return loadCart().reduce((s,i) => s + i.price * i.qty, 0); }

function fmtPrice(p) { return p.toFixed(2).replace('.',',') + ' €'; }

// Pré-remplit l'email du membre connecté dans l'URL Stripe Payment Link
function stripeUrl(link) {
  if (!link) return link;
  if (currentUser && currentUser.email) {
    var sep = link.indexOf('?') === -1 ? '?' : '&';
    return link + sep + 'prefilled_email=' + encodeURIComponent(currentUser.email);
  }
  return link;
}

// ── Modal fiche produit ────────────────────────────────────────────────────
function openProductModal(id) {
  var shop = defaultShop();
  var p = shop.albums.find(function(a){ return a.id === id; });
  if (!p) return;

  // Injecter overlay si absent
  var overlay = document.getElementById('product-modal-overlay');
  if (!overlay) {
    overlay = document.createElement('div');
    overlay.id = 'product-modal-overlay';
    overlay.innerHTML = '<div id="product-modal"><button class="pm-close" onclick="closeProductModal()">&times;</button>'
      + '<div class="pm-img-col" id="pm-img-col"></div>'
      + '<div class="pm-info-col" id="pm-info-col"></div>'
      + '</div>';
    overlay.addEventListener('click', function(e){ if (e.target === overlay) closeProductModal(); });
    document.body.appendChild(overlay);
  }

  // Image
  var img = getArtistThumb(p.imgKey);
  document.getElementById('pm-img-col').innerHTML = img
    ? '<img src="' + img + '" alt="' + esc(p.artist) + '">'
    : '<div class="pm-img-placeholder">&#9835;</div>';

  // Badge format
  var badge = p.format === 'cd'
    ? '<span class="format-badge format-cd">CD Physique</span>'
    : '<span class="format-badge format-digital">Digital</span>';

  // Stock warning
  var stockWarn = (p.format === 'cd' && p.stock !== undefined && p.stock <= 8)
    ? '<div class="pm-stock-low">&#9679; Plus que ' + p.stock + ' exemplaires</div>' : '';

  // Boutons (IDs fixes — handlers attachés après injection HTML)
  // Le bouton panier est toujours disponible ; "Acheter maintenant" reste conditionnel au lien Stripe
  var buyBtnHtml = '<button id="pm-cart-btn" class="pm-cart-btn">Ajouter au panier</button>'
    + (p.stripeLink
      ? '<button id="pm-buy-btn" class="pm-buy-btn">Acheter maintenant — ' + fmtPrice(p.price) + '</button>'
      : '<button class="pm-buy-btn" disabled>Bientôt disponible</button>');

  document.getElementById('pm-info-col').innerHTML =
      '<div class="pm-badge">' + badge + '</div>'
    + '<div class="pm-artist">' + esc(p.artist) + '</div>'
    + '<div class="pm-title">' + esc(p.title || p.name || '') + '</div>'
    + '<div class="pm-year">' + (p.year || '') + '</div>'
    + '<div class="pm-desc">' + esc(p.desc || '') + '</div>'
    + stockWarn
    + '<div class="pm-price-row"><div class="pm-price">' + fmtPrice(p.price) + '</div><div class="pm-price-sub">TTC</div></div>'
    + buyBtnHtml;

  // Attacher les handlers proprement (pas d'inline onclick, pas de problème d'échappement)
  var cartBtnEl = document.getElementById('pm-cart-btn');
  if (cartBtnEl) {
    cartBtnEl.onclick = function() {
      addToCart(p.id, 'album', p.title || p.name || '', p.artist || '', p.price, p.imgKey || '');
    };
  }
  var buyBtnEl = document.getElementById('pm-buy-btn');
  if (buyBtnEl && p.stripeLink) {
    buyBtnEl.onclick = function() {
      closeProductModal();
      requireAuthForPurchase(function() { window.location.href = stripeUrl(p.stripeLink); });
    };
  }

  // Ouvrir
  overlay.classList.add('open');
  document.body.style.overflow = 'hidden';
}

function closeProductModal() {
  var overlay = document.getElementById('product-modal-overlay');
  if (overlay) overlay.classList.remove('open');
  document.body.style.overflow = '';
}
function escHtml(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }
function getArtistThumb(key) {
  try {
    const db = JSON.parse(localStorage.getItem('harmonia_data'));
    if (!db || !db.artists) return null;
    const artist = db.artists.find(a => a.imgKey === key || (a.name||'').toLowerCase().includes((key||'').toLowerCase()));
    if (artist && artist.photo) return artist.photo;
    return null;
  } catch(e) { return null; }
}

function renderCart() {
  const cart = loadCart();
  const list = document.getElementById('cart-items-list');
  const totalEl = document.getElementById('cart-total-price');
  const checkoutBtn = document.getElementById('cart-checkout-btn');
  if (!list) return;
  if (cart.length === 0) {
    list.innerHTML = '<div class="cart-empty"><div class="cart-empty-icon">🛍</div><div>Votre panier est vide</div></div>';
    if (totalEl) totalEl.textContent = '0,00 €';
    if (checkoutBtn) checkoutBtn.disabled = true;
    return;
  }
  if (checkoutBtn) checkoutBtn.disabled = false;
  list.innerHTML = cart.map((item, idx) => {
    const img = getArtistThumb(item.imgKey);
    const imgHtml = img ? '<img src="'+img+'" alt="">' : '♫';
    return '<div class="cart-item">'
      + '<div class="cart-item-img">'+imgHtml+'</div>'
      + '<div class="cart-item-info">'
      +   '<div class="cart-item-name">'+escHtml(item.name)+'</div>'
      +   '<div class="cart-item-sub">'+escHtml(item.artist)+(item.extra?' — '+escHtml(item.extra):'')+'</div>'
      +   '<div class="cart-item-qty">'
      +     '<button class="qty-btn" onclick="changeQty('+idx+',-1)">−</button>'
      +     '<span class="qty-num">'+item.qty+'</span>'
      +     '<button class="qty-btn" onclick="changeQty('+idx+',1)">+</button>'
      +   '</div>'
      + '</div>'
      + '<div style="display:flex;flex-direction:column;align-items:flex-end;gap:6px;">'
      +   '<div class="cart-item-price">'+fmtPrice(item.price * item.qty)+'</div>'
      +   '<button class="cart-item-del" onclick="removeFromCart('+idx+')" title="Supprimer">🗑</button>'
      + '</div>'
      + '</div>';
  }).join('');
  if (totalEl) totalEl.textContent = fmtPrice(cartTotal());
  updateCartBadge();
}

function openCart() {
  var co = document.getElementById('cart-overlay');
  var cs = document.getElementById('cart-sidebar');
  if (co) co.classList.add('active');
  if (cs) cs.classList.add('open');
  document.body.style.overflow = 'hidden';
  renderCart();
}
function closeCart() {
  var co = document.getElementById('cart-overlay');
  var cs = document.getElementById('cart-sidebar');
  if (co) co.classList.remove('active');
  if (cs) cs.classList.remove('open');
  document.body.style.overflow = '';
}

/* ── MINI-CART PANEL (nav dropdown) ── */
function _injectMiniCart() {
  if (document.getElementById('mini-cart-panel')) return;
  var el = document.createElement('div');
  el.id = 'mini-cart-panel';
  el.innerHTML =
    '<div class="mini-cart-header">'
    + '<span class="mini-cart-title">PANIER</span>'
    + '<button class="mini-cart-close" onclick="closeMiniCart()" aria-label="Fermer">&times;</button>'
    + '</div>'
    + '<div id="mini-cart-body"></div>'
    + '<div class="mini-cart-footer">'
    +   '<div class="mini-cart-total-row"><span>Total</span><span id="mini-cart-total">0,00 €</span></div>'
    +   '<a href="panier.html" class="mini-cart-cta">Voir le panier</a>'
    + '</div>';
  document.body.appendChild(el);
  document.addEventListener('click', function(e) {
    var panel = document.getElementById('mini-cart-panel');
    var btn = document.getElementById('nav-cart-btn');
    if (panel && panel.classList.contains('open') && !panel.contains(e.target) && btn && !btn.contains(e.target)) {
      closeMiniCart();
    }
  });
}
function renderMiniCart() {
  var body = document.getElementById('mini-cart-body');
  var totalEl = document.getElementById('mini-cart-total');
  if (!body) return;
  var cart = loadCart();
  if (cart.length === 0) {
    body.innerHTML = '<div class="mini-cart-empty">Panier vide</div>';
    if (totalEl) totalEl.textContent = '0,00 €';
    return;
  }
  var html = cart.slice(0, 4).map(function(item, idx) {
    return '<div class="mini-cart-item">'
      + '<div class="mini-cart-item-info">'
      +   '<div class="mini-cart-item-name">' + escHtml(item.name) + '</div>'
      +   '<div class="mini-cart-item-sub">' + escHtml(item.artist) + (item.extra ? ' — ' + escHtml(item.extra) : '') + '</div>'
      + '</div>'
      + '<div class="mini-cart-item-right">'
      +   '<span class="mini-cart-item-price">' + fmtPrice(item.price * item.qty) + '</span>'
      +   '<button class="mini-cart-item-del" onclick="removeFromCart(' + idx + ');renderMiniCart();" title="Supprimer">&times;</button>'
      + '</div>'
      + '</div>';
  }).join('');
  if (cart.length > 4) {
    html += '<div class="mini-cart-more">+ ' + (cart.length - 4) + ' article(s) supplémentaire(s)</div>';
  }
  body.innerHTML = html;
  if (totalEl) totalEl.textContent = fmtPrice(cart.reduce(function(s,i){return s+i.price*i.qty;},0));
}
function openMiniCart() {
  _injectMiniCart();
  renderMiniCart();
  var panel = document.getElementById('mini-cart-panel');
  if (panel) panel.classList.add('open');
}
function closeMiniCart() {
  var panel = document.getElementById('mini-cart-panel');
  if (panel) panel.classList.remove('open');
}

function renderShopAlbums() {
  const shop = defaultShop();
  const grid = document.getElementById('shop-grid-albums');
  if (!grid) return;
  const editMode = (typeof _editModeActive !== 'undefined') && _editModeActive
    && (typeof isEditor === 'function') && isEditor();
  const albums = editMode ? shop.albums : shop.albums.filter(function(p) {
    return (typeof isItemActive === 'function') ? isItemActive('album', p.id) : true;
  });
  grid.innerHTML = albums.map(function(p) {
    const active = (typeof isItemActive === 'function') ? isItemActive('album', p.id) : true;
    const img = getArtistThumb(p.imgKey);
    const imgBlock = img
      ? '<div class="shop-card-img"><img src="' + img + '" alt="' + esc(p.artist) + '"></div>'
      : '<div class="shop-card-img"><div class="shop-card-img-placeholder"><span>&#9835;</span></div></div>';
    const badge = p.format === 'cd'
      ? '<span class="format-badge format-cd">CD Physique</span>'
      : '<span class="format-badge format-digital">Digital</span>';
    const stockWarn = (p.format === 'cd' && p.stock <= 8)
      ? '<div class="shop-stock-low">Plus que ' + p.stock + ' en stock</div>' : '';
    const inactiveBadge = !active ? '<div class="item-inactive-badge">DÉSACTIVÉ</div>' : '';
    const toggleHtml = editMode ? buildItemToggle('album', p.id, active) : '';
    const inactiveClass = !active ? ' item-card-inactive' : '';
    return '<div class="shop-card' + inactiveClass + '" data-item-type="album" data-item-id="' + p.id + '" style="position:relative;overflow:visible;cursor:pointer;" onclick="openProductModal(' + p.id + ')">'
      + imgBlock
      + '<div class="shop-card-body">'
      +   '<div class="shop-card-badges">' + badge + '</div>'
      +   '<div class="shop-card-artist">' + esc(p.artist) + '</div>'
      +   '<div class="shop-card-title">' + esc(p.title) + '</div>'
      +   '<div class="shop-card-desc">' + esc(p.desc) + '</div>'
      +   stockWarn
      +   '<div class="shop-card-footer">'
      +     '<div><div class="shop-price">' + fmtPrice(p.price) + '</div><div class="shop-price-sub">TTC</div></div>'
      +     (p.stripeLink
          ? '<button class="btn-cart" style="text-align:center;" onclick="event.stopPropagation();openProductModal(' + p.id + ')">Voir →</button>'
          : '<button class="btn-cart" style="opacity:0.45;cursor:not-allowed;" title="Bientôt disponible" disabled>Bientôt →</button>')
      +   '</div>'
      + '</div>'
      + inactiveBadge
      + toggleHtml
      + '</div>';
  }).join('');
  // Attacher handlers panier
  grid.querySelectorAll('.btn-cart[data-cid]').forEach(function(btn) {
    btn.onclick = function(e) {
      e.stopPropagation();
      addToCart(+btn.dataset.cid, 'album', btn.dataset.ctitle, btn.dataset.cartist, +btn.dataset.cprice, btn.dataset.ckey, btn.dataset.cfmt);
    };
  });
  if (editMode && typeof _attachItemToggles === 'function') _attachItemToggles();
}
function renderShopConcerts() {
  var shop = defaultShop();
  var grid = document.getElementById('shop-grid-concerts');
  if (!grid) return;
  var editMode = (typeof _editModeActive !== 'undefined') && _editModeActive
    && (typeof isEditor === 'function') && isEditor();
  var MOIS = ['JAN','FÉV','MAR','AVR','MAI','JUN','JUL','AOÛ','SEP','OCT','NOV','DÉC'];
  var concerts = editMode ? shop.concerts : shop.concerts.filter(function(c) {
    return (typeof isItemActive === 'function') ? isItemActive('concert', c.id) : true;
  });
  grid.innerHTML = concerts.map(function(c) {
    var active = (typeof isItemActive === 'function') ? isItemActive('concert', c.id) : true;
    var d = new Date(c.date + 'T00:00:00');
    var dd = d.getDate().toString().padStart(2,'0');
    var mm = MOIS[d.getMonth()];
    var yy = d.getFullYear();
    var img = getArtistThumb(c.imgKey);
    var imgBlock = img
      ? '<div class="shop-card-img"><img src="' + img + '" alt="' + esc(c.artist) + '"></div>'
      : '<div class="shop-card-img"><div class="shop-card-img-placeholder"><span>&#9835;</span></div></div>';
    var avail = c.available < 100
      ? '<div class="shop-stock-low">Plus que ' + c.available + ' places</div>' : '';
    var stdId = 'cart_c' + c.id + '_std';
    var vipId = 'cart_c' + c.id + '_vip';
    var inactiveBadge = !active ? '<div class="item-inactive-badge">DÉSACTIVÉ</div>' : '';
    var toggleHtml = editMode ? buildItemToggle('concert', c.id, active) : '';
    var inactiveClass = !active ? ' item-card-inactive' : '';
    return '<div class="shop-card' + inactiveClass + '" data-item-type="concert" data-item-id="' + c.id + '" style="position:relative;overflow:visible;">'
      + imgBlock
      + '<div class="shop-card-body">'
      +   '<div class="shop-card-badges"><span class="format-badge format-cd">' + dd + ' ' + mm + ' ' + yy + '</span></div>'
      +   '<div class="shop-card-artist">' + esc(c.artist) + '</div>'
      +   '<div class="shop-card-title">' + esc(c.venue) + '</div>'
      +   '<div class="shop-card-desc">' + esc(c.city) + ', ' + esc(c.country) + '</div>'
      +   avail
      +   '<div class="shop-card-footer">'
      +     (c.stripeLink ? '<button class="btn-cart" style="width:100%;text-align:center;" onclick="requireAuthForPurchase(function(){window.location.href=\''+esc(stripeUrl(c.stripeLink))+'\'})">Réserver →</button>' : '<button class="btn-cart" style="width:100%;opacity:0.45;cursor:not-allowed;" disabled title="Bientôt disponible">Bientôt →</button>')
      +   '</div>'
      + '</div>'
      + inactiveBadge
      + toggleHtml
      + '</div>';
  }).join('');
  // Handlers panier concerts supprimés — CTA Stripe direct
  if (editMode && typeof _attachItemToggles === 'function') _attachItemToggles();
}

let selectedStreamingPlan = 'annual';
function renderShopStreaming() {
  var shop = defaultShop();
  var s = shop.streaming;
  var container = document.getElementById('shop-streaming');
  if (!container) return;
  var saving = (s.monthly * 12 - s.annual).toFixed(2).replace('.',',');
  var mSel = selectedStreamingPlan === 'monthly' ? ' selected' : '';
  var aSel = selectedStreamingPlan === 'annual' ? ' selected' : '';
  container.innerHTML =
    '<div class="streaming-hero">'
    + '<div class="streaming-title">HARMONIA Premium</div>'
    + '<div class="streaming-desc">' + esc(s.desc) + '</div>'
    + '<ul class="streaming-features">'
    +   '<li>Catalogue complet — tous artistes</li>'
    +   '<li>Sessions studio exclusives</li>'
    +   '<li>Live &amp; inédits en avant-première</li>'
    +   '<li>Qualité audio lossless 24bit</li>'
    + '</ul>'
    + '<div class="streaming-plans">'
    +   '<div class="streaming-plan' + mSel + '" id="plan-monthly">'
    +     '<div class="streaming-plan-name">Mensuel</div>'
    +     '<div class="streaming-plan-price">' + fmtPrice(s.monthly) + '<span>/mois</span></div>'
    +   '</div>'
    +   '<div class="streaming-plan featured' + aSel + '" id="plan-annual">'
    +     '<div class="streaming-plan-name">Annuel <span class="streaming-badge">Économisez ' + fmtPrice(parseFloat(saving)) + '</span></div>'
    +     '<div class="streaming-plan-price">' + fmtPrice((s.annual/12).toFixed(2)) + '<span>/mois</span></div>'
    +     '<div style="font-size:10px;color:var(--gray);margin-top:4px;">Facturé ' + fmtPrice(s.annual) + ' par an</div>'
    +   '</div>'
    + '</div>'
    + '<button class="btn-cart" id="btn-streaming-sub" style="margin-top:24px;width:100%;padding:16px;font-size:12px;">Abonnement</button>'
    + '</div>';
  // Handlers
  var mBtn = document.getElementById('plan-monthly');
  var aBtn = document.getElementById('plan-annual');
  var subBtn = document.getElementById('btn-streaming-sub');
  if(mBtn) mBtn.onclick = function(){ selectedStreamingPlan='monthly'; renderShopStreaming(); };
  if(aBtn) aBtn.onclick = function(){ selectedStreamingPlan='annual'; renderShopStreaming(); };
  if(subBtn) {
    var price = selectedStreamingPlan === 'annual' ? s.annual : s.monthly;
    var label = selectedStreamingPlan === 'annual' ? 'Abonnement Annuel HARMONIA' : 'Abonnement Mensuel HARMONIA';
    subBtn.onclick = function(){ addToCart(9001, 'streaming', label, 'HARMONIA Premium', price, '', selectedStreamingPlan); };
  }
}
function selectStreamingPlan(plan, el) {
  selectedStreamingPlan = plan;
  document.querySelectorAll('.streaming-plan').forEach(p => p.classList.remove('selected'));
  el.classList.add('selected');
}
function addStreamingToCart() {
  const shop = defaultShop();
  const s = shop.streaming;
  const price = selectedStreamingPlan === 'monthly' ? s.monthly : s.annual;
  const label = selectedStreamingPlan === 'monthly' ? 'Abonnement Mensuel' : 'Abonnement Annuel';
  addToCart('stream-'+selectedStreamingPlan, 'streaming', label, 'HARMONIA Premium', price, 'stream', selectedStreamingPlan);
}

function switchShopTab(tab, btn) {
  document.querySelectorAll('.shop-tab').forEach(t => t.classList.remove('active'));
  document.querySelectorAll('.shop-panel').forEach(p => p.classList.remove('active'));
  if (btn) btn.classList.add('active');
  const panel = document.getElementById('shop-panel-'+tab);
  if (panel) panel.classList.add('active');
  if (tab === 'streaming') renderShopStreaming();
}

let selectedPayment = 'cb';
function openCheckout() {
  if (loadCart().length === 0) return;
  closeCart();
  document.getElementById('checkout-step-1').classList.add('active');
  document.getElementById('checkout-step-2').classList.remove('active');
  document.getElementById('checkout-step-success').classList.remove('active');
  document.getElementById('checkout-overlay').classList.add('active');
  document.body.style.overflow = 'hidden';
}
function closeCheckout() {
  document.getElementById('checkout-overlay').classList.remove('active');
  document.body.style.overflow = '';
}
function selectPayment(el) {
  document.querySelectorAll('.payment-method').forEach(m => m.classList.remove('selected'));
  el.classList.add('selected');
  selectedPayment = el.dataset.pm;
}
function checkoutNext() {
  const fn = document.getElementById('co-firstname').value.trim();
  const ln = document.getElementById('co-lastname').value.trim();
  const em = document.getElementById('co-email').value.trim();
  const errEl = document.getElementById('checkout-err-1');
  if (!fn || !ln || !em) { errEl.textContent='Veuillez remplir tous les champs obligatoires.'; errEl.style.display='block'; return; }
  if (!/^[^@]+@[^@]+\.[^@]+$/.test(em)) { errEl.textContent='Adresse e-mail invalide.'; errEl.style.display='block'; return; }
  errEl.style.display='none';
  const cart = loadCart();
  const tbody = document.getElementById('checkout-recap-body');
  const pmLabels = {cb:'CB / Stripe', paypal:'PayPal', virement:'Virement bancaire'};
  tbody.innerHTML = cart.map(item =>
    '<tr><td>'+escHtml(item.name)+(item.extra?' <small style="color:var(--gray);">('+escHtml(item.extra)+')</small>':'')+'</td>'
    +'<td style="text-align:right;color:var(--gray);">'+item.qty+'</td>'
    +'<td style="text-align:right;font-family:Georgia;">'+fmtPrice(item.price*item.qty)+'</td></tr>'
  ).join('')
  + '<tr class="checkout-total-row"><td colspan="2">Total TTC</td><td style="text-align:right;">'+fmtPrice(cartTotal())+'</td></tr>';
  const country = document.getElementById('co-country').value;
  document.getElementById('checkout-client-info').innerHTML =
    '<strong style="color:var(--white);">'+escHtml(fn)+' '+escHtml(ln)+'</strong><br>'+escHtml(em)+'<br>'+escHtml(country)+'<br>Paiement : '+escHtml(pmLabels[selectedPayment]||selectedPayment);
  document.getElementById('checkout-step-1').classList.remove('active');
  document.getElementById('checkout-step-2').classList.add('active');
}
function checkoutPrev() {
  document.getElementById('checkout-step-2').classList.remove('active');
  document.getElementById('checkout-step-1').classList.add('active');
}
function checkoutConfirm() {
  const btn = document.getElementById('checkout-confirm-btn');
  btn.textContent = 'Traitement…'; btn.disabled = true;
  setTimeout(() => {
    const cart = loadCart();
    const order = {
      id: 'HA-' + Date.now().toString(36).toUpperCase(),
      date: new Date().toISOString(),
      firstname: document.getElementById('co-firstname').value.trim(),
      lastname: document.getElementById('co-lastname').value.trim(),
      email: document.getElementById('co-email').value.trim(),
      country: document.getElementById('co-country').value,
      payment: selectedPayment,
      items: cart,
      total: cartTotal(),
      status: 'pending'
    };
    try {
      const orders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || [];
      orders.unshift(order);
      localStorage.setItem(ORDERS_KEY, JSON.stringify(orders));
    } catch(e) {}
    saveCart([]);
    document.getElementById('checkout-order-num').textContent = 'Commande n° ' + order.id;
    document.getElementById('checkout-step-2').classList.remove('active');
    document.getElementById('checkout-step-success').classList.add('active');
    btn.textContent = 'Confirmer le paiement'; btn.disabled = false;
    renderCart();
    refreshAdminOrders();
  }, 1200);
}

function refreshAdminOrders() {
  try {
    const orders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || [];
    const tbody = document.getElementById('orders-table-body');
    const emptyEl = document.getElementById('orders-empty');
    const statTotal = document.getElementById('ostat-total');
    const statCa = document.getElementById('ostat-ca');
    const statMonth = document.getElementById('ostat-month');
    if (!tbody) return;
    const now = new Date();
    const thisMonth = orders.filter(o => { const d=new Date(o.date); return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear(); });
    if (statTotal) statTotal.textContent = orders.length;
    if (statCa) statCa.textContent = fmtPrice(orders.reduce((s,o)=>s+o.total,0));
    if (statMonth) statMonth.textContent = thisMonth.length;
    if (orders.length === 0) {
      tbody.innerHTML = '';
      if (emptyEl) emptyEl.style.display='block';
      return;
    }
    if (emptyEl) emptyEl.style.display='none';
    const statusLabels = {pending:'En attente', shipped:'Expédié', cancelled:'Annulé'};
    const statusCls = {pending:'status-pending', shipped:'status-shipped', cancelled:'status-cancelled'};
    tbody.innerHTML = orders.map((o, idx) => {
      const date = new Date(o.date).toLocaleDateString('fr-FR');
      const client = escHtml((o.firstname||'')+' '+(o.lastname||''));
      const articles = o.items.map(i=>escHtml(i.name)+(i.qty>1?' ×'+i.qty:'')).join(', ');
      const status = o.status||'pending';
      return '<tr>'
        + '<td style="font-family:monospace;font-size:11px;color:var(--accent2);">'+escHtml(o.id)+'</td>'
        + '<td style="color:var(--gray);">'+date+'</td>'
        + '<td>'+client+'<br><small style="color:var(--gray);font-size:10px;">'+escHtml(o.email||'')+'</small></td>'
        + '<td style="max-width:200px;font-size:11px;color:var(--gray);">'+articles+'</td>'
        + '<td style="text-align:right;font-family:Georgia;">'+fmtPrice(o.total)+'</td>'
        + '<td><span class="order-status '+statusCls[status]+'" onclick="cycleOrderStatus('+idx+')" title="Cliquer pour changer le statut">'+statusLabels[status]+'</span></td>'
        + '</tr>';
    }).join('');
  } catch(e) {}
}

function cycleOrderStatus(idx) {
  try {
    const orders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || [];
    const cycle = ['pending','shipped','cancelled'];
    const cur = orders[idx].status || 'pending';
    orders[idx].status = cycle[(cycle.indexOf(cur)+1)%cycle.length];
    localStorage.setItem(ORDERS_KEY, JSON.stringify(orders));
    refreshAdminOrders();
  } catch(e) {}
}


// ============================================================
// HELPERS — UPLOAD PREVIEW
// ============================================================
function previewUpload(input, previewId) {
  const preview = document.getElementById(previewId);
  if (!preview) return;
  if (input.files && input.files[0]) {
    const reader = new FileReader();
    reader.onload = function(e) {
      preview.src = e.target.result;
      preview.style.display = 'block';
      const hint = document.getElementById('prod-img-hint');
      if (hint) hint.style.display = 'none';
    };
    reader.readAsDataURL(input.files[0]);
  }
}

function readFileAsBase64(input, callback) {
  if (input.files && input.files[0]) {
    const reader = new FileReader();
    reader.onload = function(e) { callback(e.target.result); };
    reader.readAsDataURL(input.files[0]);
  } else {
    callback(null);
  }
}

