      + '<td style="text-align:right;font-family:Georgia;color:var(--accent2);">'+fmtPrice(p.price)+'</td>'
      + '<td style="font-family:Arial;font-size:12px;color:'+(p.stock<5?'#e07050':'var(--gray)')+';">'+p.stock+'</td>'
      + '<td><button onclick="editProd('+p.id+')" style="background:none;border:1px solid rgba(31,158,92,0.3);color:var(--accent2);padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;margin-right:6px;">Modifier</button>'
