function saveEvt() {
  const artist = document.getElementById('evt-artist').value;
  const venue = (document.getElementById('evt-venue').value||'').trim();
  const city = (document.getElementById('evt-city').value||'').trim();
  const country = (document.getElementById('evt-country').value||'').trim();
  const date = document.getElementById('evt-date').value;
  const time = document.getElementById('evt-time').value||'20:00';
  const price = parseFloat(document.getElementById('evt-price').value)||0;
  const vip = parseFloat(document.getElementById('evt-vip').value)||0;
  const capacity = parseInt(document.getElementById('evt-capacity').value)||0;
  const desc = (document.getElementById('evt-desc').value||'').trim();
  const stripeLink = (document.getElementById('evt-stripe-link') ? document.getElementById('evt-stripe-link').value.trim() : '');
  const status = document.getElementById('evt-status').value;
  const editId = document.getElementById('evt-edit-id').value;
  if (!venue || !date) { alert('Venue et date sont requis.'); return; }
  const imgInput = document.getElementById('evt-img-input');
  function finish(imgData) {
    if (editId) {
      const idx = DB.events.findIndex(e => String(e.id) === editId);
      if (idx >= 0) {
        DB.events[idx] = Object.assign(DB.events[idx], {artist, venue, city, country, date, time, price, vip, capacity, desc, stripeLink, status});
        if (imgData) DB.events[idx].img = imgData;
      }
    } else {
      const newEvt = { id: Date.now(), artist, venue, city, country, date, time, price, vip, capacity, available: capacity, desc, stripeLink, img: imgData||null, status };
      DB.events.unshift(newEvt);
    }
    saveData(DB); renderEvts(); resetEvtForm();
  }
  if (imgInput && imgInput.files && imgInput.files[0]) {
    readFileAsBase64(imgInput, finish);
  } else {
    finish(null);
  }
}

function renderEvts() {
  const tbody = document.getElementById('evt-table-body');
  const count = document.getElementById('evt-count');
  const empty = document.getElementById('evt-empty');
  const statTotal = document.getElementById('evt-stat-total');
  const statActive = document.getElementById('evt-stat-active');
  if (!tbody) return;
  if (count) count.textContent = DB.events.length;
  if (statTotal) statTotal.textContent = DB.events.length;
  if (statActive) statActive.textContent = DB.events.filter(e=>e.status==='active'||e.status==='extended'||e.status==='rescheduled').length;
  if (DB.events.length === 0) { tbody.innerHTML=''; if(empty) empty.style.display='block'; return; }
  if (empty) empty.style.display='none';
  tbody.innerHTML = DB.events.map(e => {
    const d = e.date ? new Date(e.date).toLocaleDateString('fr-FR') : '—';
    const statusMap = {
      active:      { cls: 'status-shipped',     lbl: 'Actif' },
      cancelled:   { cls: 'status-cancelled',   lbl: 'Annulé' },
      rescheduled: { cls: 'status-rescheduled', lbl: 'Reprogrammé' },
      extended:    { cls: 'status-extended',    lbl: 'Prolongé' }
    };
    const statusCls = (statusMap[e.status] || statusMap.active).cls;
    const statusLbl = (statusMap[e.status] || statusMap.active).lbl;
    return '<tr>'
      + '<td style="font-family:Arial;font-size:11px;color:var(--accent2);">'+escHtml(d)+(e.time?' '+escHtml(e.time):'')+'</td>'
      + '<td style="color:var(--accent2);font-family:Arial;font-size:11px;">'+escHtml(e.artist)+'</td>'
      + '<td style="font-family:Georgia;">'+escHtml(e.venue)+'</td>'
      + '<td style="color:var(--gray);font-family:Arial;font-size:11px;">'+escHtml(e.city)+(e.country?', '+escHtml(e.country):'')+'</td>'
      + '<td style="text-align:right;font-family:Georgia;color:var(--accent2);">'+fmtPrice(e.price)+'</td>'
      + '<td style="text-align:right;font-family:Georgia;color:var(--accent2);">'+fmtPrice(e.vip)+'</td>'
      + '<td style="font-family:Arial;font-size:12px;color:var(--gray);">'+(e.available!=null?e.available:e.capacity)+'</td>'
      + '<td><span class="order-status '+statusCls+'">'+statusLbl+'</span></td>'
      + '<td><button onclick="editEvt('+e.id+')" style="background:none;border:1px solid rgba(31,158,92,0.3);color:var(--accent2);padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;margin-right:6px;">Modifier</button>'
      + '<button onclick="deleteEvt('+e.id+')" style="background:none;border:1px solid rgba(200,80,80,0.3);color:#e07070;padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;">Supprimer</button></td>'
      + '</tr>';
  }).join('');
}

function editEvt(id) {
  const e = DB.events.find(x => x.id === id); if (!e) return;
  const sel = document.getElementById('evt-artist');
  if(sel){for(let i=0;i<sel.options.length;i++){if(sel.options[i].value===e.artist){sel.selectedIndex=i;break;}}}
  document.getElementById('evt-venue').value = e.venue||'';
  document.getElementById('evt-city').value = e.city||'';
  document.getElementById('evt-country').value = e.country||'';
  document.getElementById('evt-date').value = e.date||'';
  document.getElementById('evt-time').value = e.time||'20:00';
  document.getElementById('evt-price').value = e.price||'';
  document.getElementById('evt-vip').value = e.vip||'';
  document.getElementById('evt-capacity').value = e.capacity||'';
  document.getElementById('evt-desc').value = e.desc||'';
  document.getElementById('evt-status').value = e.status||'active';
  document.getElementById('evt-edit-id').value = id;
  if (e.img) { const prev=document.getElementById('evt-img-preview'); if(prev){prev.src=e.img;prev.style.display='block';} }
  const title=document.getElementById('evt-form-title'); if(title) title.textContent="Modifier l'événement";
  const btn=document.querySelector('#page-shop-events .admin-btn-primary'); if(btn) btn.textContent='Enregistrer';
  const cancel=document.getElementById('evt-cancel-btn'); if(cancel) cancel.style.display='';
  document.getElementById('page-shop-events').scrollIntoView({behavior:'smooth'});
}


function cycleEvtStatus(id) {
  var e = (DB.events||[]).find(function(x){ return x.id === id; });
  if (!e) return;
  var statuts = ['active','rescheduled','extended','cancelled'];
  var labels  = ['Actif','Reprogrammé','Prolongé','Annulé'];
  var cur = statuts.indexOf(e.status||'active');
  var next = (cur + 1) % statuts.length;
  e.status = statuts[next];
  saveData(DB);
  renderEvts();
}
function deleteEvt(id) {
  if (!confirm('Supprimer cet événement ?')) return;
  DB.events = DB.events.filter(e => e.id !== id);
  saveData(DB); renderEvts();
}

// ============================================================
// LIENS PAIEMENT
// ============================================================
function refreshPLinkItems() {
  const sel = document.getElementById('plink-item');
  if (!sel) return;
  let opts = '<option value="">— Sélectionner —</option>';
  if (DB.products && DB.products.length) {
    opts += '<optgroup label="Produits">' + DB.products.map(p => '<option value="prod:'+p.id+':'+p.price+'">'+escHtml(p.artist+' — '+p.name+' ('+fmtPrice(p.price)+')')+'</option>').join('') + '</optgroup>';
  }
  if (DB.events && DB.events.length) {
    opts += '<optgroup label="Événements">' + DB.events.map(e => '<option value="evt:'+e.id+':'+e.price+'">'+escHtml(e.artist+' — '+e.venue+' '+e.date+' ('+fmtPrice(e.price)+')')+'</option>').join('') + '</optgroup>';
  }
  sel.innerHTML = opts;
}

function fillPLinkPrice() {
  const sel = document.getElementById('plink-item');
  if (!sel || !sel.value) return;
  const parts = sel.value.split(':');
  const price = parseFloat(parts[2])||0;
  document.getElementById('plink-price').value = price.toFixed(2);
  updatePLinkTotal();
}

function updatePLinkTotal() {
  const qty = parseInt(document.getElementById('plink-qty').value)||1;
  const price = parseFloat(document.getElementById('plink-price').value)||0;
  const total = qty * price;
  document.getElementById('plink-total').textContent = fmtPrice(total);
}

function generatePaymentLink() {
  const itemSel = document.getElementById('plink-item');
  const email = (document.getElementById('plink-email').value||'').trim();
  const msg = (document.getElementById('plink-msg').value||'').trim();
  const qty = parseInt(document.getElementById('plink-qty').value)||1;
  const price = parseFloat(document.getElementById('plink-price').value)||0;
  if (!itemSel.value) { alert('Sélectionnez un article.'); return; }
  if (!email) { alert("L'email destinataire est requis."); return; }
  const parts = itemSel.value.split(':');
  const itemType = parts[0];
  const itemId = parts[1];
  const total = qty * price;
  let itemName = '';
  if (itemType === 'prod') {
    const p = DB.products.find(x => String(x.id) === itemId);
    itemName = p ? (p.artist+' — '+p.name) : 'Produit';
  } else {
    const e = DB.events.find(x => String(x.id) === itemId);
    itemName = e ? (e.artist+' — '+e.venue) : 'Événement';
  }
  const linkId = Math.random().toString(36).substr(2,8).toUpperCase();
  const encodedItem = encodeURIComponent(itemName.replace(/[^a-zA-Z0-9 -]/g,'').substr(0,30));
  const url = 'https://pay.harmonia-music.com/order?id='+linkId+'&amount='+total.toFixed(2)+'&item='+encodedItem;
  const subject = 'Votre lien de paiement HARMONIA';
  const body = (msg ? msg+'\n\n' : '') + 'Article : '+itemName+'\nQuantité : '+qty+'\nMontant total : '+fmtPrice(total)+'\n\nLien de paiement sécurisé :\n'+url+'\n\nCe lien est personnel et non transférable.\n\n— HARMONIA Production';
  const mailtoUrl = 'mailto:'+encodeURIComponent(email)+'?subject='+encodeURIComponent(subject)+'&body='+encodeURIComponent(body);
  const link = { id: linkId, date: new Date().toISOString(), email, itemName, total, url, status: 'sent', qty };
  DB.paymentLinks.unshift(link);
  saveData(DB);
  const box = document.getElementById('plink-url');
  if (box) box.textContent = url;
  const result = document.getElementById('plink-result');
  if (result) result.style.display='block';
  window.location.href = mailtoUrl;
  renderPLinks();
}

function copyPLink() {
  const box = document.getElementById('plink-url');
  if (!box) return;
  navigator.clipboard.writeText(box.textContent).then(() => {
    const btn = box.nextElementSibling;
    if (btn) { const orig=btn.textContent; btn.textContent='✓ Copié !'; btn.style.background='rgba(31,158,92,0.2)'; setTimeout(()=>{btn.textContent=orig;btn.style.background='';},1500); }
  }).catch(() => { alert('Lien : '+box.textContent); });
}

function renderPLinks() {
  const tbody = document.getElementById('plink-table-body');
  const count = document.getElementById('plink-count');
  const empty = document.getElementById('plink-empty');
  if (!tbody) return;
  if (count) count.textContent = DB.paymentLinks.length;
  if (DB.paymentLinks.length === 0) { tbody.innerHTML=''; if(empty) empty.style.display='block'; return; }
  if (empty) empty.style.display='none';
  tbody.innerHTML = DB.paymentLinks.map((l, idx) => {
    const d = new Date(l.date).toLocaleDateString('fr-FR');
    const statusCls = l.status==='paid' ? 'status-shipped' : 'status-pending';
    const statusLbl = l.status==='paid' ? 'Payé' : 'Envoyé';
    const shortUrl = l.url.length>50 ? l.url.substr(0,50)+'...' : l.url;
    return '<tr>'
      + '<td style="font-family:Arial;font-size:11px;color:var(--gray);">'+escHtml(d)+'</td>'
      + '<td style="font-family:Arial;font-size:11px;color:var(--accent2);">'+escHtml(l.email)+'</td>'
      + '<td style="font-family:Georgia;font-size:12px;">'+escHtml(l.itemName)+'</td>'
      + '<td style="text-align:right;font-family:Georgia;color:var(--accent2);">'+fmtPrice(l.total)+'</td>'
      + '<td style="font-family:monospace;font-size:10px;color:var(--gray);max-width:180px;overflow:hidden;text-overflow:ellipsis;" title="'+escHtml(l.url)+'">'+escHtml(shortUrl)+'</td>'
      + '<td><span class="order-status '+statusCls+'" onclick="togglePLinkPaid('+idx+')" title="Cliquer pour changer">'+statusLbl+'</span></td>'
      + '<td><button onclick="editPLink('+l.id+')" style="background:none;border:1px solid rgba(31,158,92,0.3);color:var(--accent2);padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;margin-right:4px;">Modifier statut</button>'
      + '<button onclick="copyPLinkFromHistory('+idx+')" style="background:none;border:1px solid rgba(31,158,92,0.3);color:var(--accent2);padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;margin-right:4px;">Copier</button>'
      + '<button onclick="deletePLink('+idx+')" style="background:none;border:1px solid rgba(200,80,80,0.3);color:#e07070;padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;">Suppr.</button></td>'
      + '</tr>';
  }).join('');
}

function togglePLinkPaid(idx) {
  if (!DB.paymentLinks[idx]) return;
  DB.paymentLinks[idx].status = DB.paymentLinks[idx].status === 'paid' ? 'sent' : 'paid';
  saveData(DB); renderPLinks();
}

function deletePLink(idx) {
  if (!confirm('Supprimer ce lien ?')) return;
  DB.paymentLinks.splice(idx, 1);
  saveData(DB); renderPLinks();
}

function copyPLinkFromHistory(idx) {
  const l = DB.paymentLinks[idx]; if (!l) return;
  navigator.clipboard.writeText(l.url).catch(() => { alert(l.url); });
}

// ============================================================
// CLIENTS
// ============================================================
function mergeCustomersFromOrders() {
  try {
    const orders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || [];
    orders.forEach(o => {
      if (!o.email) return;
      const existing = DB.customers.find(c => c.email === o.email);
      if (!existing) {
        DB.customers.push({
          id: Date.now() + Math.random(),
          firstname: o.firstname||'',
          lastname: o.lastname||'',
          email: o.email,
          country: o.country||'',
          phone: '',
          createdAt: o.date || new Date().toISOString(),
          fromOrder: true
        });
      }
    });
  } catch(e) {}
}

function addCustomer() {
  const firstname = (document.getElementById('cust-firstname').value||'').trim();
  const lastname = (document.getElementById('cust-lastname').value||'').trim();
  const email = (document.getElementById('cust-email').value||'').trim();
  const country = (document.getElementById('cust-country').value||'').trim();
  const phone = (document.getElementById('cust-phone').value||'').trim();
  if (!email) { alert('Email requis.'); return; }
  if (DB.customers.find(c => c.email === email)) { alert('Ce client existe déjà.'); return; }
  DB.customers.unshift({ id: Date.now(), firstname, lastname, email, country, phone, createdAt: new Date().toISOString(), fromOrder: false });
  saveData(DB);
  ['cust-firstname','cust-lastname','cust-email','cust-country','cust-phone'].forEach(id => { const el=document.getElementById(id); if(el) el.value=''; });
  renderCustomers();
}

function renderCustomers() {
  mergeCustomersFromOrders();
  const tbody = document.getElementById('cust-table-body');
  const count = document.getElementById('cust-count');
  const empty = document.getElementById('cust-empty');
  const search = (document.getElementById('cust-search').value||'').toLowerCase();
  const statTotal = document.getElementById('cust-stat-total');
  const statOrders = document.getElementById('cust-stat-orders');
  if (!tbody) return;
  let orders = [];
  try { orders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || []; } catch(e) {}
  const filtered = DB.customers.filter(c => {
    if (!search) return true;
    return (c.firstname+' '+c.lastname).toLowerCase().includes(search) || (c.email||'').toLowerCase().includes(search);
  });
  if (count) count.textContent = filtered.length;
  if (statTotal) statTotal.textContent = DB.customers.length;
  const withOrders = DB.customers.filter(c => orders.some(o => o.email === c.email));
  if (statOrders) statOrders.textContent = withOrders.length;
  if (filtered.length === 0) { tbody.innerHTML=''; if(empty) empty.style.display='block'; return; }
  if (empty) empty.style.display='none';
  tbody.innerHTML = filtered.map((c, idx) => {
    const custOrders = orders.filter(o => o.email === c.email);
    const totalSpent = custOrders.reduce((s,o)=>s+o.total,0);
    const d = c.createdAt ? new Date(c.createdAt).toLocaleDateString('fr-FR') : '—';
    const realIdx = DB.customers.findIndex(x => x.id === c.id);
    return '<tr>'
      + '<td style="font-family:Georgia;">'+escHtml((c.firstname||'')+' '+(c.lastname||''))+'</td>'
      + '<td style="font-family:Arial;font-size:11px;color:var(--accent2);">'+escHtml(c.email)+'</td>'
      + '<td style="color:var(--gray);font-family:Arial;font-size:11px;">'+escHtml(c.country||'—')+'</td>'
      + '<td style="font-family:Arial;font-size:12px;text-align:center;">'+custOrders.length+'</td>'
      + '<td style="text-align:right;font-family:Georgia;color:var(--accent2);">'+(totalSpent>0?fmtPrice(totalSpent):'—')+'</td>'
      + '<td style="color:var(--gray);font-family:Arial;font-size:11px;">'+escHtml(d)+'</td>'
      + '<td>'
      + '<button onclick="editCustomer(\''+c.id+'\')" style="background:none;border:1px solid rgba(31,158,92,0.3);color:var(--accent2);padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;margin-right:4px;">Modifier</button>'
      + '<button onclick="emailCustomer('+realIdx+')" style="background:none;border:1px solid rgba(31,158,92,0.3);color:var(--accent2);padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;margin-right:4px;">Email</button>'
      + '<button onclick="deleteCustomer('+realIdx+')" style="background:none;border:1px solid rgba(200,80,80,0.3);color:#e07070;padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;">Suppr.</button>'
      + '</td>'
      + '</tr>';
  }).join('');
}

function emailCustomer(idx) {
  const c = DB.customers[idx]; if (!c) return;
  window.location.href = 'mailto:'+encodeURIComponent(c.email)+'?subject='+encodeURIComponent('HARMONIA Production');
}

function deleteCustomer(idx) {
  if (!confirm('Supprimer ce client ?')) return;
  DB.customers.splice(idx, 1);
  saveData(DB); renderCustomers();
}

function exportCustomersCSV() {
  let orders = [];
  try { orders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || []; } catch(e) {}
  const rows = [['Prénom','Nom','Email','Pays','Téléphone','Commandes','Total dépensé','Date inscription']];
  DB.customers.forEach(c => {
    const custOrders = orders.filter(o => o.email === c.email);
    const totalSpent = custOrders.reduce((s,o)=>s+o.total,0);
    rows.push([c.firstname||'',c.lastname||'',c.email||'',c.country||'',c.phone||'',custOrders.length,totalSpent.toFixed(2),c.createdAt?new Date(c.createdAt).toLocaleDateString('fr-FR'):'']);
  });
  downloadCSV(rows, 'harmonia-clients.csv');
}

// ============================================================
// ORDERS — enhanced refresh & CSV
// ============================================================
function refreshAdminOrders() {
  try {
    const allOrders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || [];
    const filterEl = document.getElementById('orders-status-filter');
    const filterVal = filterEl ? filterEl.value : 'all';
    const orders = filterVal === 'all' ? allOrders : allOrders.filter(o => (o.status||'pending') === filterVal);
    const tbody = document.getElementById('orders-table-body');
    const emptyEl = document.getElementById('orders-empty');
    const statTotal = document.getElementById('ostat-total');
    const statCa = document.getElementById('ostat-ca');
    const statMonth = document.getElementById('ostat-month');
    const statAvg = document.getElementById('ostat-avg');
    if (!tbody) return;
    const now = new Date();
    const thisMonth = allOrders.filter(o => { const d=new Date(o.date); return d.getMonth()===now.getMonth()&&d.getFullYear()===now.getFullYear(); });
    const ca = allOrders.reduce((s,o)=>s+o.total,0);
    const avg = allOrders.length ? ca/allOrders.length : 0;
    if (statTotal) statTotal.textContent = allOrders.length;
    if (statCa) statCa.textContent = fmtPrice(ca);
    if (statMonth) statMonth.textContent = thisMonth.length;
    if (statAvg) statAvg.textContent = fmtPrice(avg);
    if (orders.length === 0) {
      tbody.innerHTML = '';
      if (emptyEl) emptyEl.style.display='block';
      return;
    }
    if (emptyEl) emptyEl.style.display='none';
    const statusLabels = {pending:'En attente', shipped:'Expédié', cancelled:'Annulé'};
    const statusCls = {pending:'status-pending', shipped:'status-shipped', cancelled:'status-cancelled'};
    tbody.innerHTML = orders.map((o, idx) => {
      const realIdx = allOrders.indexOf(o);
      const date = new Date(o.date).toLocaleDateString('fr-FR');
      const client = escHtml((o.firstname||'')+' '+(o.lastname||''));
      const articles = o.items.map(i=>escHtml(i.name)+(i.qty>1?' ×'+i.qty:'')).join(', ');
      const status = o.status||'pending';
      return '<tr>'
        + '<td style="font-family:monospace;font-size:11px;color:var(--accent2);">'+escHtml(o.id)+'</td>'
        + '<td style="color:var(--gray);">'+date+'</td>'
        + '<td>'+client+'<br><small style="color:var(--gray);font-size:10px;">'+escHtml(o.email||'')+'</small></td>'
        + '<td style="max-width:200px;font-size:11px;color:var(--gray);">'+articles+'</td>'
        + '<td style="text-align:right;font-family:Georgia;">'+fmtPrice(o.total)+'</td>'
        + '<td><span class="order-status '+statusCls[status]+'" onclick="cycleOrderStatus('+realIdx+')" title="Cliquer pour changer le statut">'+statusLabels[status]+'</span></td>'
        + '<td><button onclick="editOrder(\''+escHtml(o.id)+'\')" style="background:none;border:1px solid rgba(31,158,92,0.3);color:var(--accent2);padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;margin-right:4px;">Modifier</button>'
        + '<button onclick="sendOrderConfirmation('+realIdx+')" style="background:none;border:1px solid rgba(31,158,92,0.3);color:var(--accent2);padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;margin-right:4px;">Confirmation</button>'
        + '<button onclick="deleteOrder(\''+escHtml(o.id)+'\')" style="background:none;border:1px solid rgba(200,80,80,0.3);color:#e07070;padding:5px 10px;font-family:Arial;font-size:9px;letter-spacing:1px;cursor:pointer;">Suppr.</button></td>'
        + '</tr>';
    }).join('');
  } catch(e) {}
}

function sendOrderConfirmation(idx) {
  try {
    const orders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || [];
    const o = orders[idx]; if (!o || !o.email) { alert('Email client introuvable.'); return; }
    const articles = o.items.map(i=>i.name+(i.qty>1?' ×'+i.qty:'')).join(', ');
    const body = 'Bonjour '+o.firstname+',\n\nNous confirmons votre commande :\n\nN° '+o.id+'\nArticles : '+articles+'\nTotal : '+fmtPrice(o.total)+'\n\nMerci de votre confiance.\n\n— HARMONIA Production';
    window.location.href = 'mailto:'+encodeURIComponent(o.email)+'?subject='+encodeURIComponent('Confirmation commande HARMONIA — '+o.id)+'&body='+encodeURIComponent(body);
  } catch(e) {}
}

function exportOrdersCSV() {
  try {
    const orders = JSON.parse(localStorage.getItem(ORDERS_KEY)) || [];
    const rows = [['N° Commande','Date','Prénom','Nom','Email','Articles','Total','Statut']];
    orders.forEach(o => {
      const articles = o.items.map(i=>i.name+(i.qty>1?' ×'+i.qty:'')).join(' | ');
      rows.push([o.id, new Date(o.date).toLocaleDateString('fr-FR'), o.firstname||'', o.lastname||'', o.email||'', articles, o.total.toFixed(2), o.status||'pending']);
    });
    downloadCSV(rows, 'harmonia-commandes.csv');
  } catch(e) {}
}

function editOrder(orderId) {
  var orders = JSON.parse(localStorage.getItem(ORDERS_KEY) || '[]');
  var o = orders.find(function(x){ return x.id === orderId; });
  if (!o) return;
  var labels = {pending:'En attente', shipped:'Expédié', cancelled:'Annulé'};
  var current = labels[o.status||'pending'] || o.status || 'En attente';
  var newStatusLabel = prompt('Statut (En attente / Expédié / Annulé) :', current);
  if (newStatusLabel === null) return;
  var reverse = {'En attente':'pending','Expédié':'shipped','Annulé':'cancelled'};
  o.status = reverse[newStatusLabel.trim()] || o.status;
  localStorage.setItem(ORDERS_KEY, JSON.stringify(orders));
  refreshAdminOrders();
}

function editPLink(id) {
  var pl = (DB.paymentLinks||[]).find(function(x){ return x.id === id; });
  if (!pl) return;
  var statuts = ['sent','paid','cancelled'];
  var current = statuts.indexOf(pl.status);
  pl.status = statuts[(current + 1) % statuts.length];
  saveData(DB);
  renderPLinks();
}

function refreshCustomersList() {
  var orders = [];
  try { orders = JSON.parse(localStorage.getItem(ORDERS_KEY) || '[]'); } catch(e) {}
  orders.forEach(function(o) {
    var email = o.email || (o.customer && o.customer.email);
    if (!email) return;
    var exists = (DB.customers||[]).find(function(c){ return c.email === email; });
    if (!exists) {
      DB.customers = DB.customers || [];
      DB.customers.push({
        id: Date.now() + Math.random(),
        firstname: o.firstname || (o.customer && o.customer.firstname) || '',
        lastname:  o.lastname  || (o.customer && o.customer.lastname)  || '',
        email: email,
        country: o.country || (o.customer && o.customer.country) || '',
        phone: '',
        createdAt: o.date || new Date().toISOString().split('T')[0]
      });
    }
  });
  saveData(DB);
  renderCustomers();
}

function editCustomer(id) {
  var c = (DB.customers||[]).find(function(x){ return String(x.id) === String(id); });
  if (!c) return;
  document.getElementById('cust-firstname').value = c.firstname || '';
  document.getElementById('cust-lastname').value  = c.lastname  || '';
  document.getElementById('cust-email').value     = c.email     || '';
  document.getElementById('cust-country').value   = c.country   || '';
  document.getElementById('cust-phone').value     = c.phone     || '';
  window._editCustomerId = String(id);
  var btn = document.getElementById('cust-save-btn');
  if (btn) btn.textContent = 'Enregistrer modifications';
  var cancelBtn = document.getElementById('cust-cancel-btn');
  if (cancelBtn) cancelBtn.style.display = '';
  showAdminPage('customers-admin');
}

function saveCustomer() {
  var fn = (document.getElementById('cust-firstname').value||'').trim();
  var ln = (document.getElementById('cust-lastname').value||'').trim();
  var em = (document.getElementById('cust-email').value||'').trim();
  var co = (document.getElementById('cust-country').value||'').trim();
  var ph = (document.getElementById('cust-phone').value||'').trim();
  if (!em) { alert('Email requis.'); return; }
  DB.customers = DB.customers || [];
  if (window._editCustomerId) {
    var idx = DB.customers.findIndex(function(c){ return String(c.id) === window._editCustomerId; });
    if (idx !== -1) {
      DB.customers[idx].firstname = fn;
      DB.customers[idx].lastname  = ln;
      DB.customers[idx].email     = em;
      DB.customers[idx].country   = co;
      DB.customers[idx].phone     = ph;
    }
    window._editCustomerId = null;
    var btn = document.getElementById('cust-save-btn');
    if (btn) btn.textContent = 'Ajouter le client';
  } else {
    if (DB.customers.find(function(c){ return c.email === em; })) { alert('Email déjà enregistré.'); return; }
    DB.customers.push({
      id: Date.now(),
      firstname: fn, lastname: ln, email: em, country: co, phone: ph,
      createdAt: new Date().toISOString().split('T')[0]
    });
  }
  saveData(DB);
  ['cust-firstname','cust-lastname','cust-email','cust-country','cust-phone'].forEach(function(fid){
    var el = document.getElementById(fid); if (el) el.value = '';
  });
  var cancelBtn = document.getElementById('cust-cancel-btn');
  if (cancelBtn) cancelBtn.style.display = 'none';
  renderCustomers();
}

function resetCustForm() {
  ['cust-firstname','cust-lastname','cust-email','cust-country','cust-phone'].forEach(function(fid){
    var el = document.getElementById(fid); if (el) el.value = '';
  });
  window._editCustomerId = null;
  var btn = document.getElementById('cust-save-btn');
  if (btn) btn.textContent = 'Ajouter le client';
  var cb = document.getElementById('cust-cancel-btn');
  if (cb) cb.style.display = 'none';
}

function editUser(id) {
  var u = (DB.users||[]).find(function(x){ return x.id === id; });
  if (!u) return;
  if (isProtectedUser(u)) {
    var _ep = prompt('Compte protégé — mot de passe administrateur requis :');
    if (_ep !== 'Music7') { alert('Mot de passe incorrect.'); return; }
  }
  var ulEl = document.getElementById('u-login'); if (ulEl) ulEl.value = u.login || '';
  var ueEl = document.getElementById('u-email'); if (ueEl) ueEl.value = u.email || '';
  document.getElementById('u-pass').value  = '';
  document.getElementById('u-name').value  = u.name  || '';
  var roleEl = document.getElementById('u-role');
  if (roleEl) roleEl.value = u.role || 'viewer';
  if (u.permissions) {
    document.querySelectorAll('.perm-chk').forEach(function(chk) {
      var sec = chk.dataset.section; var act = chk.dataset.action;
      chk.checked = !!(u.permissions[sec] && u.permissions[sec][act]);
    });
  }
  window._editUserId = id;
  var btn = document.querySelector('#page-users-admin .admin-btn-sm[onclick="saveUser()"]');
  if (btn) btn.textContent = 'Enregistrer modifications';
  showAdminPage('users-admin');
}

function downloadCSV(rows, filename) {
  const csv = rows.map(r => r.map(v => '"'+String(v).replace(/"/g,'""')+'"').join(',')).join('\n');
  const blob = new Blob([csv], {type:'text/csv;charset=utf-8;'});
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.click();
  setTimeout(() => URL.revokeObjectURL(url), 1000);
}

document.addEventListener('DOMContentLoaded', function() {
  applyModules();       // re-applique après rendu complet du DOM
  applyLang();
  renderShopAlbums();
  renderShopConcerts();
  updateCartBadge();
  _injectMiniCart();
  renderMiniCart();

  // Nav glassmorphism scroll state
  (function() {
    var nav = document.querySelector('nav');
    if (!nav) return;
    var threshold = 40;
    var onScroll = function() {
      if (window.scrollY > threshold) nav.classList.add('scrolled');
      else nav.classList.remove('scrolled');
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
  })();
});


// ========================
// ========================
// PREVIEW MODE — Va et viens admin ↔ site
// ========================
var _previewMode = false;
var _adminScrollPos = 0;

function togglePreviewMode() {
  _previewMode = !_previewMode;
  var adminOverlay = document.getElementById('admin-overlay');
  var previewBar   = document.getElementById('admin-preview-bar');
  var btn          = document.getElementById('preview-toggle-btn');
  var btnLabel     = document.getElementById('preview-btn-label');
  var userLabel    = document.getElementById('preview-username');

  if (_previewMode) {
    // Mémoriser position scroll admin
    if (adminOverlay) _adminScrollPos = adminOverlay.scrollTop;
    // Masquer overlay admin
    if (adminOverlay) adminOverlay.style.display = 'none';
    // Débloquer le scroll du body pour voir tout le site
    document.body.style.overflow = '';
    document.body.style.paddingBottom = '60px'; // espace pour la barre preview
    // Afficher la barre preview
    if (previewBar) previewBar.classList.add('visible');
    if (userLabel && currentUser) userLabel.textContent = currentUser.name;
    if (btn) btn.classList.add('site-mode');
    if (btnLabel) btnLabel.textContent = '← Retour Admin';
    // Aller en haut du site
    window.scrollTo({ top: 0, behavior: 'smooth' });
    // Re-rendre tous les blocs publics avec données fraîches
    if (typeof renderArtists === 'function') renderArtists();
    if (typeof renderCatalogueByCategory === 'function') renderCatalogueByCategory();
    if (typeof renderNews === 'function') renderNews();
    if (typeof renderShopAlbums === 'function') renderShopAlbums();
    if (typeof renderShopConcerts === 'function') renderShopConcerts();
    if (typeof applyLang === 'function') applyLang();
  } else {
    // Retour admin : réafficher l'overlay
    document.body.style.overflow = 'hidden';
    document.body.style.paddingBottom = '';
    if (adminOverlay) {
      adminOverlay.style.display = 'block';
      // Restaurer position scroll admin
      setTimeout(function(){ adminOverlay.scrollTop = _adminScrollPos; }, 50);
    }
    if (previewBar) previewBar.classList.remove('visible');
    if (btn) btn.classList.remove('site-mode');
    if (btnLabel) btnLabel.textContent = 'Voir le site';
    // Rafraîchir les listes admin
    if (typeof refreshAdminLists === 'function') refreshAdminLists();
    if (typeof updateStats === 'function') updateStats();
  }
}









function discoverSite() {
  var splash = document.getElementById('splash');
  if (!splash) return;

  // Trouver position du disque dans le logo (SVG large dans splash)
  var svgEl = splash.querySelector('svg[aria-label="HARMONIA"]');
  var rect = svgEl ? svgEl.getBoundingClientRect() : null;

  // Position centrale approximative du disque (proportionnelle au SVG)
  var cx = rect ? (rect.left + rect.width * 0.56) : window.innerWidth / 2;
  var cy = rect ? (rect.top  + rect.height * 0.48) : window.innerHeight / 2;

  // Taille du cercle pour couvrir tout l'écran
  var maxDist = Math.max(
    Math.hypot(cx, cy),
    Math.hypot(window.innerWidth - cx, cy),
    Math.hypot(cx, window.innerHeight - cy),
    Math.hypot(window.innerWidth - cx, window.innerHeight - cy)
  );
  var size = maxDist * 2.2;

  // Faire tourner le disque dans le logo
  var diskGroup = svgEl ? svgEl.querySelectorAll('g') : [];
  if (diskGroup.length > 0) {
    diskGroup.forEach(function(g) { g.style.animation = 'diskSpin 0.5s linear infinite'; });
  }

  // Créer / positionner le cercle de transition
  var vt = document.getElementById('vinyl-transition');
  vt.style.display = 'block';
  vt.style.width  = size + 'px';
  vt.style.height = size + 'px';
  vt.style.left   = cx + 'px';
  vt.style.top    = cy + 'px';
  vt.style.transform = 'translate(-50%, -50%) scale(0)';
  vt.style.opacity = '1';
  vt.style.transition = 'transform 0.65s cubic-bezier(0.4,0,0.2,1), opacity 0.3s ease 0.55s';

  // Délai court puis expansion
  setTimeout(function() {
    vt.style.transform = 'translate(-50%, -50%) scale(1)';
  }, 80);

  // Au pic de l'expansion : faire disparaître le splash
  setTimeout(function() {
    splash.style.opacity = '0';
    splash.style.transition = 'opacity 0.2s ease';
  }, 500);

  // Débloquer le scroll et commencer à effacer le cercle
  setTimeout(function() {
    document.body.style.overflow = '';
    vt.style.opacity = '0';
  }, 650);

  // Nettoyage final
  setTimeout(function() {
    splash.style.display = 'none';
    vt.style.display = 'none';
  }, 980);
}

// Bloquer scroll pendant splash
(function() {
  var s = document.getElementById('splash');
  if (s) document.body.style.overflow = 'hidden';
})();

// ========================
// ARTIST DEDICATED PAGE
// ========================
var _currentArtistPage = null;

function openArtistPage(id) {
  var a = DB.artists.find(function(x){ return x.id === id; });
  if (!a) return;
  _currentArtistPage = id;
  var page = document.getElementById('artist-page');
  var img = artistImg(a);

  // Réseaux sociaux
  var socials = [
    a.instagram && '<a href="'+a.instagram+'" target="_blank" rel="noopener">Instagram</a>',
    a.facebook  && '<a href="'+a.facebook+'"  target="_blank" rel="noopener">Facebook</a>',
    a.youtube   && '<a href="'+a.youtube+'"   target="_blank" rel="noopener">YouTube</a>',
    a.spotify   && '<a href="'+a.spotify+'"   target="_blank" rel="noopener">Spotify</a>'
  ].filter(Boolean).join('');

  // ── Albums depuis DB.albums (filtrés par artiste) ──
  var artistAlbums = DB.albums.filter(function(al){
    return al.artist && al.artist.toLowerCase() === a.name.toLowerCase();
  });

  // Morceaux depuis DB.tracks (filtrés par artiste)
  var artistTracks = DB.tracks.filter(function(t){
    return t.artist && t.artist.toLowerCase() === a.name.toLowerCase();
  });

  // Construire HTML accordéon Albums
  function buildAlbumsHtml() {
    if (!artistAlbums.length) return '';
    var html = '<div class="ap-section"><div class="ap-section-title">Albums</div><div class="ap-albums-accordion">';
    artistAlbums.forEach(function(al, idx) {
      var albumTracks = artistTracks.filter(function(t){ return t.album === al.title; });
      var coverHtml = al.cover
        ? '<img src="'+al.cover+'" alt="'+esc(al.title)+'" style="width:100%;height:100%;object-fit:cover;">'
        : '<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:28px;color:var(--accent2);">♪</div>';
      var albumId = 'album-acc-'+id+'-'+idx;

      // Ligne de morceaux
      var tracksHtml = '';
      if (albumTracks.length) {
        tracksHtml = albumTracks.map(function(t, ti) {
          var ytUrl  = t.ytId ? 'https://www.youtube.com/watch?v='+t.ytId : '';
          var spUrl  = t.spotify || al.spotify || a.spotify || '';
          return '<div class="ap-track-row">'
            + '<span class="ap-track-num">'+(ti+1)+'</span>'
            + '<div class="ap-track-info">'
            +   '<span class="ap-track-title">'+esc(t.title)+'</span>'
            +   (t.style ? '<span class="ap-track-genre">'+esc(t.style)+'</span>' : '')
            + '</div>'
            + '<span class="ap-track-dur">'+esc(t.duration||'')+'</span>'
            + '<div class="ap-track-links">'
            +   (ytUrl ? '<a href="'+ytUrl+'" target="_blank" rel="noopener" class="ap-track-btn ap-track-yt" title="YouTube">▶ YouTube</a>' : '')
            +   (spUrl ? '<a href="'+spUrl+'" target="_blank" rel="noopener" class="ap-track-btn ap-track-sp" title="Spotify">Spotify</a>' : '')
            + '</div>'
            + '</div>';
        }).join('');
      } else {
        tracksHtml = '<div style="color:var(--gray);font-size:12px;padding:16px 0;font-family:Arial;letter-spacing:1px;">Morceaux à venir</div>';
      }

      html += '<div class="ap-album-item" id="'+albumId+'">'
        + '<div class="ap-album-header" data-album-id="'+albumId+'" onclick="toggleAlbumAccordion(this.dataset.albumId)">'
        +   '<div class="ap-album-cover-sm">'+coverHtml+'</div>'
        +   '<div class="ap-album-meta">'
        +     '<div class="ap-album-title-acc">'+esc(al.title)+'</div>'
        +     '<div class="ap-album-sub">'+al.year+' · '+esc(al.genre||'')+(al.label?' · '+esc(al.label):'')+'</div>'
        +     (al.desc ? '<div class="ap-album-desc-acc">'+esc(al.desc)+'</div>' : '')
        +   '</div>'
        +   '<div class="ap-album-links">'
        +     (al.spotify ? '<a href="'+al.spotify+'" target="_blank" rel="noopener" class="ap-track-btn ap-track-sp" onclick="event.stopPropagation()">Spotify</a>' : '')
        +   '</div>'
        +   '<span class="ap-album-chevron">▾</span>'
        + '</div>'
        + '<div class="ap-album-tracks" style="display:none;">'
        +   '<div class="ap-tracks-header">'
        +     '<span style="width:32px;">#</span>'
        +     '<span style="flex:1;">Titre</span>'
        +     '<span>Durée</span>'
        +     '<span>Écouter</span>'
        +   '</div>'
        +   tracksHtml
        + '</div>'
        + '</div>';
    });
    html += '</div></div>';
    return html;
  }

  // YouTube
  var ytHtml = (a.youtubeVideos||[]).map(function(v, i){
    var thumb = 'https://img.youtube.com/vi/'+v.ytId+'/hqdefault.jpg';
    return '<div class="ap-yt-card" id="ytcard-'+i+'-'+id+'" onclick="playArtistYT(this.dataset.ytid,this.id)" data-ytid="'+v.ytId+'">'
      + '<div class="ap-yt-thumb">'
      +   '<img src="'+thumb+'" alt="'+esc(v.title)+'" loading="lazy">'
      +   '<div class="ap-yt-play"><div class="ap-yt-play-btn"><svg viewBox="0 0 24 24"><path d="M8 5v14l11-7z"/></svg></div></div>'
      + '</div>'
      + '<div class="ap-yt-info"><div class="ap-yt-title">'+esc(v.title)+'</div></div>'
      + '</div>';
  }).join('');

  page.innerHTML =
    '<button class="ap-back" onclick="closeArtistPage()">← Retour</button>'
    + '<div class="ap-hero">'
    +   (img ? '<img class="ap-photo" src="'+img+'" alt="'+esc(a.name)+'">' : '<div class="ap-photo" style="background:var(--navy);"></div>')
    +   '<div class="ap-hero-info">'
    +     '<div class="ap-label">HARMONIA Records · '+esc(a.origin||'Cabo Verde')+'</div>'
    +     '<div class="ap-name">'+esc(a.name)+'</div>'
    +     '<div class="ap-style">'+esc(a.style||'')+'</div>'
    +     '<div class="ap-bio">'+esc(a.bioLong||a.bioShort||'')+'</div>'
    +     (socials ? '<div class="ap-social">'+socials+'</div>' : '')
    +   '</div>'
    + '</div>'
    + buildAlbumsHtml()
    + (ytHtml ? '<div class="ap-section"><div class="ap-section-title">Vidéos</div><div class="ap-yt-grid">'+ytHtml+'</div></div>' : '');

  page.style.display = 'block';
  page.style.animation = 'none';
  page.offsetHeight;
  page.style.animation = '';
  document.body.style.overflow = 'hidden';
  window.location.hash = 'artiste-'+id;
}

function toggleAlbumAccordion(albumId) {
  var item = document.getElementById(albumId);
  if (!item) return;
  var tracks  = item.querySelector('.ap-album-tracks');
  var chevron = item.querySelector('.ap-album-chevron');
  var isOpen  = tracks.style.display !== 'none';
  // Fermer tous
  document.querySelectorAll('.ap-album-tracks').forEach(function(t){ t.style.display='none'; });
  document.querySelectorAll('.ap-album-chevron').forEach(function(c){ c.style.transform=''; });
  document.querySelectorAll('.ap-album-item').forEach(function(i){ i.classList.remove('open'); });
  // Ouvrir celui cliqué si pas déjà ouvert
  if (!isOpen) {
    tracks.style.display = 'block';
    if (chevron) chevron.style.transform = 'rotate(180deg)';
    item.classList.add('open');
  }
}

function closeArtistPage() {
  var page = document.getElementById('artist-page');
  if (page) page.style.display = 'none';
  document.body.style.overflow = '';
  window.location.hash = 'artists';
  _currentArtistPage = null;
}

function playArtistYT(ytId, cardId) {
  var card = document.getElementById(cardId);
  if (!card) return;
  card.innerHTML = '<div class="ap-yt-iframe-wrap"><iframe src="https://www.youtube.com/embed/'+ytId+'?autoplay=1&rel=0" allow="autoplay;encrypted-media" allowfullscreen></iframe></div>';
}

// ========================
// ADMIN — Discographie & YouTube
// ========================
var _discoArtistId = null;

function openDiscoAdmin(artistId) {
  _discoArtistId = artistId;
  var a = DB.artists.find(function(x){ return x.id === artistId; });
  if (!a) return;
  var sec = document.getElementById('disco-admin-section');
  var ytSec = document.getElementById('yt-admin-section');
  if (sec) { sec.style.display = 'block'; document.getElementById('disco-artist-name').textContent = a.name; }
  if (ytSec) { ytSec.style.display = 'block'; document.getElementById('yt-artist-name').textContent = a.name; }
  renderDiscoList(artistId);
  renderYTList(artistId);
  sec && sec.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function renderDiscoList(artistId) {
  var a = DB.artists.find(function(x){ return x.id === artistId; });
  if (!a) return;
  var el = document.getElementById('disco-list');
  if (!el) return;
  if (!(a.discography||[]).length) { el.innerHTML = '<p style="color:var(--gray);font-size:12px;">Aucun album.</p>'; return; }
  el.innerHTML = a.discography.map(function(al, i){
    return '<div style="display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid rgba(31,158,92,0.08);">'
      + (al.cover ? '<img src="'+al.cover+'" style="width:40px;height:40px;object-fit:cover;">' : '<div style="width:40px;height:40px;background:var(--navy2);"></div>')
      + '<div style="flex:1;"><div style="font-family:Georgia;font-size:13px;color:var(--white);">'+esc(al.title)+'</div><div style="font-size:11px;color:var(--accent2);">'+al.year+'</div></div>'
      + '<button class="admin-btn-sm danger" onclick="removeDiscoAlbum('+artistId+','+i+')">Supprimer</button>'
      + '</div>';
  }).join('');
}

function renderYTList(artistId) {
  var a = DB.artists.find(function(x){ return x.id === artistId; });
  if (!a) return;
  var el = document.getElementById('yt-list');
  if (!el) return;
  if (!(a.youtubeVideos||[]).length) { el.innerHTML = '<p style="color:var(--gray);font-size:12px;">Aucune vid\u00e9o.</p>'; return; }
  el.innerHTML = (a.youtubeVideos||[]).map(function(v, i){
    return '<div style="display:flex;align-items:center;gap:12px;padding:10px 0;border-bottom:1px solid rgba(31,158,92,0.08);">'
      + '<img src="https://img.youtube.com/vi/'+v.ytId+'/default.jpg" style="width:60px;height:40px;object-fit:cover;">'
      + '<div style="flex:1;font-family:Arial;font-size:12px;color:var(--white);">'+esc(v.title)+'<br><span style="color:var(--accent2);font-size:10px;">'+v.ytId+'</span></div>'
      + '<button class="admin-btn-sm danger" onclick="removeArtistYT('+artistId+','+i+')">Supprimer</button>'
      + '</div>';
  }).join('');
}

function addDiscoAlbum() {
  var title = (document.getElementById('disco-title').value||'').trim();
  var year  = parseInt(document.getElementById('disco-year').value)||new Date().getFullYear();
  var desc  = (document.getElementById('disco-desc').value||'').trim();
  var spot  = (document.getElementById('disco-spotify').value||'').trim();
  var prev  = document.getElementById('disco-cover-preview');
  var cover = (prev && prev.src && prev.src.startsWith('data:')) ? prev.src : '';
  if (!title) { alert('Titre requis.'); return; }
  var a = DB.artists.find(function(x){ return x.id === _discoArtistId; });
  if (!a) return;
  a.discography = a.discography || [];
  a.discography.push({ title:title, year:year, cover:cover, desc:desc, spotify:spot });
  saveData(DB);
  renderDiscoList(_discoArtistId);
  ['disco-title','disco-year','disco-desc','disco-spotify'].forEach(function(id){ var el=document.getElementById(id); if(el) el.value=''; });
  if(prev){ prev.src=''; prev.style.display='none'; }
}

function removeDiscoAlbum(artistId, idx) {
  if (!confirm('Supprimer cet album ?')) return;
  var a = DB.artists.find(function(x){ return x.id === artistId; });
  if (!a || !a.discography) return;
  a.discography.splice(idx, 1);
  saveData(DB); renderDiscoList(artistId);
}

function addArtistYT() {
  var ytId  = (document.getElementById('yt-id-input').value||'').trim();
  var title = (document.getElementById('yt-title-input').value||'').trim();
  if (!ytId) { alert('ID YouTube requis.'); return; }
  var a = DB.artists.find(function(x){ return x.id === _discoArtistId; });
  if (!a) return;
  a.youtubeVideos = a.youtubeVideos || [];
  a.youtubeVideos.push({ ytId:ytId, title:title||ytId });
  saveData(DB);
  renderYTList(_discoArtistId);
  document.getElementById('yt-id-input').value = '';
  document.getElementById('yt-title-input').value = '';
}

function removeArtistYT(artistId, idx) {
  if (!confirm('Supprimer cette vid\u00e9o ?')) return;
  var a = DB.artists.find(function(x){ return x.id === artistId; });
  if (!a || !a.youtubeVideos) return;
  a.youtubeVideos.splice(idx, 1);
  saveData(DB); renderYTList(artistId);
}



function renderMusicCategoriesList() {
  var el = document.getElementById('cat-list');
  var counter = document.getElementById('cat-count');
  if (!el) return;
  var cats = DB.musicCategories || [];
  if (counter) counter.textContent = cats.length;
  if (!cats.length) { el.innerHTML = '<p style="color:var(--gray);font-size:12px;">Aucune catégorie.</p>'; return; }
  el.innerHTML = cats.map(function(cat, i) {
    var fixed = cat.id === 'traditional' || cat.id === 'urban';
    return '<div style="display:flex;align-items:center;gap:12px;padding:12px 0;border-bottom:1px solid rgba(31,158,92,0.08);">'
      + '<div style="flex:1;">'
      +   '<div style="font-family:Georgia;font-size:14px;color:var(--white);">'+esc(cat.label)+'</div>'
      +   '<div style="font-size:11px;color:var(--accent2);letter-spacing:2px;">'+esc(cat.id)+'</div>'
      + '</div>'
      + (fixed ? '<span style="font-size:10px;color:var(--gray);font-family:Arial;">Défaut</span>'
               : '<button class="admin-btn-sm danger" onclick="deleteMusicCategory('+i+')">Supprimer</button>')
      + '</div>';
  }).join('');
}

function addMusicCategory() {
  var id    = (document.getElementById('cat-id').value||'').trim().toLowerCase().replace(/\s+/g,'-');
  var label = (document.getElementById('cat-label').value||'').trim();
  if (!id || !label) { alert('Identifiant et nom requis.'); return; }
  if ((DB.musicCategories||[]).find(function(c){ return c.id === id; })) { alert('Cet identifiant existe déjà.'); return; }
  DB.musicCategories = DB.musicCategories || [];
  DB.musicCategories.push({ id:id, label:label, color:'rgba(200,200,200,0.1)', textColor:'#ffffff', borderColor:'rgba(200,200,200,0.2)' });
  saveData(DB);
  renderMusicCategoriesList();
  document.getElementById('cat-id').value = '';
  document.getElementById('cat-label').value = '';
  renderCatalogueByCategory();
}

function deleteMusicCategory(idx) {
  var cat = (DB.musicCategories||[])[idx];
  if (!cat || cat.id==='traditional' || cat.id==='urban') return;
  if (!confirm('Supprimer la catégorie "'+cat.label+'" ?')) return;
  DB.musicCategories.splice(idx, 1);
  saveData(DB);
  renderMusicCategoriesList();
  renderCatalogueByCategory();
}



function goToCatalogueAlbum(albumTitle) {
  closeArtistPage();
  // Aller à la section music
  setTimeout(function() {
    var sec = document.getElementById('music');
    if (sec) sec.scrollIntoView({ behavior: 'smooth' });
    // Chercher l'album dans toutes les catégories et l'ouvrir
    setTimeout(function() {
      var tracks = DB.tracks.filter(function(t){ return t.album === albumTitle; });
      if (!tracks.length) return;
      var firstTrack = tracks[0];
      var key = encodeURIComponent(firstTrack.album + '|' + firstTrack.artist);
      openAlbumTracklist(key, firstTrack.category||'traditional');
    }, 600);
  }, 400);
}

// ================================================
// MOTEUR DE RECHERCHE GLOBAL
// ================================================
function openSearch() {
  var overlay = document.getElementById('search-overlay');
  if (!overlay) return;
  var wasActive = overlay.classList.contains('active');
  if (wasActive) { closeSearch(); return; }
  overlay.classList.add('active');
  // Ne pas bloquer le scroll — la page reste lisible derrière
  var inp = document.getElementById('search-input');
  if (inp) { inp.value = ''; inp.focus(); }
  document.getElementById('search-results').innerHTML = '';
  // Fermeture au clic extérieur
  setTimeout(function() {
    document.addEventListener('mousedown', _searchOutsideHandler);
  }, 10);
}

function _searchOutsideHandler(e) {
  var overlay = document.getElementById('search-overlay');
  var btn = document.querySelector('.nav-search-btn');
  if (overlay && !overlay.contains(e.target) && (!btn || !btn.contains(e.target))) {
    closeSearch();
  }
}

function closeSearch() {
  var overlay = document.getElementById('search-overlay');
  if (overlay) overlay.classList.remove('active');
  document.removeEventListener('mousedown', _searchOutsideHandler);
}

function searchNav(el) {
  closeSearch();
  var href = el.getAttribute('data-href');
  if (href) window.location.href = href;
}

// Normalise accents + casse pour comparaison insensible
function norm(s) {
  return (s||'').normalize('NFD').replace(/[̀-ͯ]/g,'').toLowerCase();
}

function doSearch(q) {
  q = norm(q).trim();
  var res = document.getElementById('search-results');
  if (!res) return;
  if (!q) { res.innerHTML = ''; return; }

  var html = '';
  var found = 0;
  var lang = (typeof currentLang !== 'undefined') ? currentLang : 'fr';

  function matches() {
    for (var i=0; i<arguments.length; i++) { if (norm(arguments[i]).includes(q)) return true; }
    return false;
  }

  function item(icon, title, sub, tag, href, extraBtn) {
    return '<div class="search-result-item" style="cursor:pointer;" onclick="searchNav(this)" data-href="' + (href||'') + '">'
      + '<div class="search-result-icon">' + icon + '</div>'
      + '<div class="search-result-main">'
      +   '<div class="search-result-title">' + title + '</div>'
      +   '<div class="search-result-sub">' + sub + '</div>'
      + '</div>'
      + (extraBtn || ('<span class="search-result-tag">' + tag + '</span>'))
      + '</div>';
  }

  // ── Pages statiques du site ──
  var t = (typeof TRANSLATIONS !== 'undefined' && TRANSLATIONS[lang]) ? TRANSLATIONS[lang] : {};
  var staticPages = [
    { label: 'José da Silva',   sub: 'Fondateur · Producteur · HARMONIA',
      href: 'jose-da-silva.html', icon: '★',
      keys: ['José da Silva','jose da silva','fondateur','producteur','harmonia','découvreur','talent','cabo verde',
             t.founder_bio||'', t.about_p1||''] },
    { label: 'Cesária Évora',   sub: 'Diva aux pieds nus · Morna · Cabo Verde',
      href: 'cesaria.html', icon: '♫',
      keys: ['Cesária Évora','cesaria evora','cesaria','morna','diva','pieds nus','sobreviventi',
             t.cesaria_bio1||'', t.cesaria_bio2||'', t.cesaria_quote||''] },
    { label: 'Qui sommes-nous', sub: 'Histoire · Identité · HARMONIA',
      href: 'qui-sommes-nous.html', icon: '🏠',
      keys: ['qui sommes nous','histoire','identite','harmonia','production','musicale','cabo verde','archipel',
             t.about_p1||'', t.about_p2||'', t.about_p3||'', t.about_p4||''] },
    { label: 'Catalogue Musique', sub: 'Morceaux · Styles · Écouter',
      href: 'musique.html', icon: '🎵',
      keys: ['musique','catalogue','morceaux','ecouter','streaming','morna','funana','batuque','coladeira'] },
    { label: 'Événements',      sub: 'Concerts · Agenda · Billetterie',
      href: 'evenements.html', icon: '📅',
      keys: ['evenements','concerts','agenda','billetterie','spectacle','tournee','dates'] },
    { label: 'Boutique',        sub: 'Albums · Merch · Streaming · Billets',
      href: 'boutique.html', icon: '🛍',
      keys: ['boutique','shop','acheter','album','merch','merchandising','billets','streaming','produit'] },
    { label: 'Contact',         sub: 'Adresse · Email · Formulaire',
      href: 'contact.html', icon: '✉',
      keys: ['contact','adresse','email','formulaire','message','telephone','siège'] },
    { label: 'Artistes',        sub: 'Roster · Tous les artistes',
      href: 'artistes.html', icon: '♪',
      keys: ['artistes','roster','artiste','chanteur','chanteuse','musicien'] },
    { label: 'Actualités',      sub: 'News · Presse · Blog',
      href: 'actualites.html', icon: '📰',
      keys: ['actualites','news','presse','blog','article'] }
  ];
  var pagesFound = staticPages.filter(function(p) {
    return matches(p.label, p.sub) || p.keys.some(function(k){ return norm(k).includes(q); });
  });
  if (pagesFound.length) {
    html += '<div class="search-section-label">Pages</div>';
    html += pagesFound.map(function(p) {
      return item(p.icon, esc(p.label), esc(p.sub), 'Page', p.href);
    }).join('');
    found += pagesFound.length;
  }

  // ── Artistes (DB) ──
  var artists = DB.artists.filter(function(a) {
    return matches(a.name, a.origin, a.style, a.bioShort, a.bioLong,
      (a.discography||[]).map(function(d){return d.title+' '+d.desc;}).join(' '));
  });
  if (artists.length) {
    html += '<div class="search-section-label">Artistes</div>';
    html += artists.map(function(a) {
      return item('♪', esc(a.name),
        esc(a.origin||'') + (a.style ? ' · ' + esc(a.style) : ''),
        'Artiste', 'artistes.html?artist=' + a.id);
    }).join('');
    found += artists.length;
  }

  // ── Albums ──
  var albums = DB.albums.filter(function(al) {
    return matches(al.title, al.artist, al.genre, al.desc, al.label);
  });
  if (albums.length) {
    html += '<div class="search-section-label">Albums</div>';
    html += albums.map(function(al) {
      return item('💿', esc(al.title),
        esc(al.artist||'') + ' · ' + al.year + (al.genre ? ' · ' + esc(al.genre) : ''),
        'Album', 'boutique.html');
    }).join('');
    found += albums.length;
  }

  // ── Morceaux ──
  var tracks = DB.tracks.filter(function(t) {
    return matches(t.title, t.artist, t.album, t.style, t.category);
  });
  if (tracks.length) {
    html += '<div class="search-section-label">Morceaux</div>';
    html += tracks.map(function(t) {
      var ytBtn = t.ytId
        ? '<a href="https://www.youtube.com/watch?v=' + t.ytId + '" target="_blank" rel="noopener" class="search-result-tag ap-track-yt" onclick="event.stopPropagation()">▶ YouTube</a>'
        : null;
      return item('🎵', esc(t.title),
        esc(t.artist||'') + ' · ' + esc(t.album||'') + (t.duration ? ' · ' + t.duration : ''),
        'Morceau', 'musique.html', ytBtn);
    }).join('');
    found += tracks.length;
  }

  // ── Actualités ──
  if (DB.news && DB.news.length) {
    var newsItems = DB.news.filter(function(n) {
      var title   = (typeof n.title   === 'object' ? (n.title[lang]   || n.title.fr   || '') : (n.title||''));
      var excerpt = (typeof n.excerpt === 'object' ? (n.excerpt[lang] || n.excerpt.fr || '') : (n.excerpt||''));
      return matches(title, excerpt, n.category, n.artist);
    });
    if (newsItems.length) {
      html += '<div class="search-section-label">Actualités</div>';
      html += newsItems.map(function(n) {
        var title = (typeof n.title === 'object' ? (n.title[lang] || n.title.fr || '') : (n.title||''));
        return item('📰', esc(title),
          (n.date||'') + (n.category ? ' · ' + esc(n.category) : ''),
          'Actualité', 'actualites.html');
      }).join('');
      found += newsItems.length;
    }
  }

  // ── Événements ──
  if (DB.events && DB.events.length) {
    var evts = DB.events.filter(function(e) {
      return matches(e.title, e.artist, e.venue, e.city, e.country, e.desc);
    });
    if (evts.length) {
      html += '<div class="search-section-label">Événements</div>';
      html += evts.map(function(e) {
        return item('📅', esc(e.title||e.artist||''),
          esc(e.venue||'') + ' · ' + esc(e.city||e.country||'') + ' · ' + esc(e.date||''),
          'Événement', 'evenements.html');
      }).join('');
      found += evts.length;
    }
  }

  // ── Produits shop ──
  var allProds = [];
  if (DB.products) {
    (DB.products.albums||[]).forEach(function(p){ allProds.push({icon:'💿',name:p.title||p.name,sub:esc(p.artist||'')+(p.price?' · '+p.price+' €':''),href:'boutique.html',keys:[p.title,p.name,p.artist,p.desc,p.genre]}); });
    (DB.products.merch||[]).forEach(function(p){ allProds.push({icon:'👕',name:p.name,sub:p.price?p.price+' €':'',href:'boutique.html?tab=merch',keys:[p.name,p.desc,p.category]}); });
  }
  var prodsFound = allProds.filter(function(p){ return p.keys.some(function(k){return matches(k);}); });
  if (prodsFound.length) {
    html += '<div class="search-section-label">Boutique</div>';
    html += prodsFound.map(function(p){ return item(p.icon, esc(p.name), p.sub, 'Produit', p.href); }).join('');
    found += prodsFound.length;
  }

  if (!found) {
    html = '<div class="search-empty">Aucun résultat pour « ' + esc(q.normalize ? q : q) + ' »</div>';
  }

  res.innerHTML = html;
}

// Fermer sur Escape
document.addEventListener('keydown', function(e) {
  if (e.key === 'Escape') closeSearch();
});

